-- Seed English translations for all terms
-- Chapters 1-7, 16, and Epilogue (17)

-- ═══════════════════════════════════════
-- Chapter 1: Into the World of Computers
-- ═══════════════════════════════════════

UPDATE terms SET
  one_liner_en = 'A way to represent numbers using only 0s and 1s',
  definition_en = 'A number system that computers understand. While we normally use 10 digits (0–9), computers can only distinguish between ON and OFF states of electricity, so they express everything using just 0 and 1.',
  mechanism_en = 'Electricity flowing is represented as "1" and not flowing as "0." Using combinations of these two states, computers represent numbers, letters, images, music, and all other data. For example, the decimal number "5" becomes "101" in binary.',
  analogy_en = 'Similar to Morse code''s dots and dashes. Just two types of symbols can convey any message—the same principle applies here.',
  pitfall_en = 'People tend to think "binary is old technology." In reality, modern smartphones and supercomputers all fundamentally run on binary.'
WHERE id = 'binary';

UPDATE terms SET
  one_liner_en = 'The smallest unit of information—a single 0 or 1',
  definition_en = 'Short for Binary digit. The smallest unit of information a computer handles, holding a value of either 0 or 1.',
  mechanism_en = 'A single bit can only represent 2 possibilities (0 or 1), but adding more bits doubles the possibilities each time. 2 bits = 4 combinations (00, 01, 10, 11), 3 bits = 8 combinations, and so on.',
  analogy_en = 'Like a single light switch. ON or OFF, Yes or No—the smallest unit that can record one "yes/no" answer.',
  pitfall_en = '"Bit" and "Byte" are easily confused. A bit is the smallest unit; a byte is a group of 8 bits. Network speed uses "bps (bits per second)" while file size uses "bytes."'
WHERE id = 'bit';

UPDATE terms SET
  one_liner_en = 'A group of 8 bits—enough to represent one character',
  definition_en = 'A unit of 8 bits grouped together. Used as the basic unit for measuring data size. One byte can represent 256 different values (2 to the power of 8).',
  mechanism_en = 'With 8 bits, you can express numbers from 0 to 255 or a single alphabet letter. File sizes are measured in KB (kilobytes ≈ 1,000 bytes), MB (megabytes ≈ 1 million bytes), GB (gigabytes ≈ 1 billion bytes).',
  analogy_en = 'If a bit is one LEGO block, a byte is a basic part made of 8 blocks. You combine these basic parts to build larger creations (data).',
  pitfall_en = 'Completely unrelated to the Japanese word for "part-time job." Also, "Mbps" in network speed is mega"bits" while "MB" in file size is mega"bytes"—an 8x difference, so be careful.'
WHERE id = 'byte';

UPDATE terms SET
  one_liner_en = 'A lookup table that converts characters to numbers',
  definition_en = 'Short for American Standard Code for Information Interchange. A character encoding standard for computers, assigning numbers 0–127 to each character.',
  mechanism_en = 'For example, "A" is 65, "B" is 66, "a" is 97. Alphabets, digits, and symbols each have assigned numbers. Internally, computers communicate using these numbers (converted to binary).',
  analogy_en = 'An international "phone book for characters." Because computers worldwide share the convention that "65 means A," they can exchange data.',
  pitfall_en = 'ASCII is designed for English, so it cannot represent Japanese. Japanese requires different encodings like Shift-JIS or UTF-8. UTF-8 is becoming the global standard.'
WHERE id = 'ascii';

UPDATE terms SET
  one_liner_en = 'The language of 0s and 1s that computers directly understand',
  definition_en = 'A set of instructions that a CPU can directly execute. Composed entirely of 0s and 1s, it''s very hard for humans to read, but it''s the only language computers understand.',
  mechanism_en = 'Programs we write (in Python, JavaScript, etc.) are ultimately converted to machine language before the CPU executes them. Compilers and interpreters handle this conversion.',
  analogy_en = 'Like learning a foreign language—ultimately you need to speak the other person''s native tongue. Machine language is the computer''s "mother tongue," and all programming languages are eventually translated into it.',
  pitfall_en = '"You can''t program without learning machine language" is a misconception. Modern high-level languages (Python, JavaScript) are automatically converted to machine language for you.'
WHERE id = 'machine-language';

UPDATE terms SET
  one_liner_en = 'Instructions written in a programming language',
  definition_en = 'Instructions for a computer written in a programming language. In a human-readable format, it is later converted to machine language for execution. Also called "source code."',
  mechanism_en = 'Code is saved as a text file and converted to machine language by a compiler or interpreter. Writing an instruction like print("Hello") displays text on the screen.',
  analogy_en = 'A cooking recipe. Like writing out steps—"chop onions → sauté → add salt"—the computer follows this recipe exactly.',
  pitfall_en = '"Code" can also mean a cipher, but in programming it means "instructions." "Coding" refers to the act of writing code.'
WHERE id = 'code';

UPDATE terms SET
  one_liner_en = 'A collection of instructions for a computer',
  definition_en = 'A collection of code (instructions) that performs a specific process. It tells the computer "what" to do and "in what order."',
  mechanism_en = 'A program is saved as a file. When executed, it''s loaded into memory and the CPU processes the instructions in sequence.',
  analogy_en = 'Like a sports day program (schedule). "1. Opening ceremony → 2. Sprint race → 3. Ball toss…" — a "to-do list" for the computer with tasks and their order.',
  pitfall_en = 'The difference between "program" and "app" can be confusing. An app is a type of program—specifically one with a particular purpose.'
WHERE id = 'program';

UPDATE terms SET
  one_liner_en = 'A program made for a specific purpose',
  definition_en = 'Short for Application. Software that users use for specific tasks. There are various apps for different purposes: calculators, notepads, games, etc.',
  mechanism_en = 'Apps run on top of an OS, receiving user input, processing it, and displaying results on screen. Types include smartphone apps, web apps, and desktop apps.',
  analogy_en = 'Individual tools in a toolbox. Hammer (calculator app), saw (notepad app), measuring tape (maps app)—each has its specialty.',
  pitfall_en = 'People often equate "app" with "software." An app is a type of software. Software also includes OSes and drivers, which aren''t apps.'
WHERE id = 'app';

UPDATE terms SET
  one_liner_en = 'All programs that run on a computer',
  definition_en = 'A general term for programs that run on a computer. Includes apps, OSes, drivers, and more. Refers to invisible programs, as opposed to physical hardware.',
  mechanism_en = 'Software runs on hardware (like a PC) and tells the hardware what to do. A computer only functions when both hardware and software are present.',
  analogy_en = 'The "mind" or "thoughts" of a human. A body (hardware) without a mind (software) can''t move. Conversely, a mind alone without a body can''t do anything.',
  pitfall_en = '"Software ≠ apps." There are many types of software that users don''t directly interact with, like OSes and firmware.'
WHERE id = 'software';

UPDATE terms SET
  one_liner_en = 'A container for saving data',
  definition_en = 'The unit for saving and managing data on a computer. Documents, images, music, programs—all data is saved as files.',
  mechanism_en = 'Files have a name (filename) and an extension indicating their type. Examples: report.txt, photo.jpg. Files are organized into folders (directories).',
  analogy_en = 'Same concept as a paper clear file folder. Just as you organize documents into folders, you store data in files.',
  pitfall_en = 'People tend to think "deleted files can be recovered." Once you empty the trash, recovery is generally very difficult. Back up important files.'
WHERE id = 'file';

-- ═══════════════════════════════════════
-- Chapter 2: File Kingdom Library
-- ═══════════════════════════════════════

UPDATE terms SET
  one_liner_en = 'A format that saves only plain text without formatting',
  definition_en = 'A file format that saves plain text (pure character strings without formatting). The most basic format that any computer can open.',
  mechanism_en = 'Stores only character data, with no formatting like bold or color. Can be created and edited with Notepad or any text editor.',
  analogy_en = 'A note written with a black pen on white paper. No colors or decorations—just simple text, but anyone can read it.',
  pitfall_en = 'Saving in Word creates a .docx, not .txt. To get a pure text file, you need to specify the format via "Save As."'
WHERE id = 'txt';

UPDATE terms SET
  one_liner_en = 'A text format that adds formatting with simple symbols',
  definition_en = 'A Markdown format file. While being plain text, it uses symbols like # and * to express structure like headings and bullet points.',
  mechanism_en = '# for headings, * or - for bullet points, ** for bold, [text](URL) for links. Widely used in GitHub READMEs and documentation.',
  analogy_en = 'A standardized version of personal note-taking conventions. Like turning "● means bullet point" and "underline means emphasis" into a shared format.',
  pitfall_en = 'You need to learn Markdown syntax, but knowing 5–6 symbols is enough for basics. # heading, - list, **bold** are the most important.'
WHERE id = 'md';

UPDATE terms SET
  one_liner_en = 'A format that creates the skeleton of web pages',
  definition_en = 'Short for HyperText Markup Language. A language for describing the structure of web pages, using "tags" to wrap elements like headings, paragraphs, links, and images.',
  mechanism_en = 'Uses tags like <html>, <body>, <h1>, <p> to define document structure. A browser reads this file and displays it as a web page.',
  analogy_en = 'Like a house blueprint showing "here is a pillar," "here is a wall," "here is a door." HTML indicates "here is a heading," "here is a paragraph," "here is a link."',
  pitfall_en = 'HTML alone looks plain. You need CSS for colors and layout. Remember: HTML is the "skeleton," CSS is the "interior design."'
WHERE id = 'html-file';

UPDATE terms SET
  one_liner_en = 'A format that styles the appearance of web pages',
  definition_en = 'Short for Cascading Style Sheets. A language for specifying visual styles—colors, sizes, layout—for HTML structures.',
  mechanism_en = 'Select targets with selectors and specify styles with properties and values. Example: h1 { color: blue; } means "make h1 tags blue."',
  analogy_en = 'Interior design for a house. Wallpaper colors, furniture placement, lighting brightness—the role of making everything look beautiful.',
  pitfall_en = 'CSS''s "C" stands for Cascading, meaning later-written styles take priority. Not understanding this "override rule" causes confusion.'
WHERE id = 'css-file';

UPDATE terms SET
  one_liner_en = 'A program format that adds interactivity to web pages',
  definition_en = 'A program file written in JavaScript. Adds interactive behavior to web pages—clicks, animations, data processing, and more.',
  mechanism_en = 'The browser loads .js files along with HTML and executes them. They can respond to user actions and communicate with servers.',
  analogy_en = 'The "mechanism" installer for a house. Open a door and lights turn on, press a button and music plays—creating dynamic features.',
  pitfall_en = '"Java" and "JavaScript" are completely different. They just have similar names—their syntax and purposes are different.'
WHERE id = 'js-file';

UPDATE terms SET
  one_liner_en = 'JavaScript made safer with type annotations',
  definition_en = 'A file written in TypeScript, a language that adds "types" to JavaScript for safer, more maintainable code.',
  mechanism_en = 'You can specify types for variables and function parameters, and errors are caught when wrong types are used. Ultimately compiled to JavaScript for execution.',
  analogy_en = 'A form with fixed fields. "Numbers go here," "text goes here"—having defined fields prevents entry mistakes.',
  pitfall_en = 'There''s a learning curve, but for large projects, it reduces bugs and ultimately saves time.'
WHERE id = 'ts-file';

UPDATE terms SET
  one_liner_en = 'A format for organizing and storing data',
  definition_en = 'Short for JavaScript Object Notation. A lightweight data format that structures data as "key-value pairs." Widely used in config files and API communication.',
  mechanism_en = '{ } for objects, [ ] for arrays. Can nest strings, numbers, booleans, null, objects, and arrays to create structured data.',
  analogy_en = 'An organized business card holder. Information arranged with labels like "Name: XX," "Phone: YY," "Address: ZZ."',
  pitfall_en = 'JSON doesn''t support comments. If you want to add notes to config files, consider other formats like YAML.'
WHERE id = 'json-file';

UPDATE terms SET
  one_liner_en = 'A compressed image format ideal for photographs',
  definition_en = 'An image format created by the Joint Photographic Experts Group. Efficiently compresses photos with many colors. One of the most widely used image formats.',
  mechanism_en = 'Uses "lossy compression" to reduce file size by discarding information imperceptible to the human eye. Quality gradually degrades with repeated saves.',
  analogy_en = 'Same idea as converting CD music to MP3. Trimming parts humans can''t notice to make files lighter.',
  pitfall_en = 'Repeatedly editing and saving causes quality degradation. Keep originals separate and only save the final version as JPG.'
WHERE id = 'jpg-file';

UPDATE terms SET
  one_liner_en = 'A high-quality image format that supports transparency',
  definition_en = 'Short for Portable Network Graphics. Supports transparency and doesn''t lose quality with repeated saves.',
  mechanism_en = 'Uses "lossless compression," compressing without quality loss. Can store transparency (alpha channel), making it ideal for logos and icons with transparent backgrounds.',
  analogy_en = 'A document in a transparent clear file. The background shows through, so you can layer it on top of other images.',
  pitfall_en = 'Tends to have larger file sizes than JPG. Use JPG for photos, PNG for logos, icons, and screenshots.'
WHERE id = 'png-file';

UPDATE terms SET
  one_liner_en = 'A vector image that stays crisp no matter how much you zoom in',
  definition_en = 'Short for Scalable Vector Graphics. A vector format that represents shapes using mathematical formulas. Stays perfectly sharp at any zoom level.',
  mechanism_en = 'Defines shapes with formulas like "draw a line from coordinate (100,50) to (200,150)." Rendered by calculation at display time, so it''s always sharp regardless of size.',
  analogy_en = 'Like a blueprint or technical drawing. Since it''s a set of instructions—"draw a line here, draw a circle here"—it reproduces accurately at any print size.',
  pitfall_en = 'Not suitable for complex images like photographs. Best for simple icons, logos, shapes, and charts.'
WHERE id = 'svg-file';

UPDATE terms SET
  one_liner_en = 'A document format that looks the same on any device',
  definition_en = 'Short for Portable Document Format. Displays with the same layout on any device or OS. Ideal for sharing print-ready documents.',
  mechanism_en = 'Embeds all fonts, images, and layout information into the file. Displays exactly as the creator intended, regardless of the viewing environment.',
  analogy_en = 'A printed page digitized. Like paper, anyone who views it sees the same layout.',
  pitfall_en = 'Intentionally difficult to edit. For editing, use the original Word or design file, then output the final version as PDF.'
WHERE id = 'pdf-file';

UPDATE terms SET
  one_liner_en = 'A tabular data format separated by commas',
  definition_en = 'Short for Comma-Separated Values. The simplest tabular data format, with data separated by commas. Can be opened in spreadsheet software like Excel.',
  mechanism_en = 'Each line is one record, and commas mark column boundaries. Example: name,age,occupation',
  analogy_en = 'A table without grid lines. Commas serve as markers saying "the column changes here."',
  pitfall_en = 'If data contains commas, they get confused with delimiters. In that case, wrap the data in double quotes like "data,here".'
WHERE id = 'csv-file';

UPDATE terms SET
  one_liner_en = 'A human-readable configuration file format',
  definition_en = 'Short for YAML Ain''t Markup Language. A configuration file format that uses indentation to express structure, designed to be easy for humans to read.',
  mechanism_en = 'Uses indentation (e.g., 2 spaces) for hierarchy and "key: value" format. Can express the same data structures as JSON but more readably. Supports comments.',
  analogy_en = 'A neatly organized notebook. The indentation makes the hierarchy clear, so you can grasp the structure at a glance.',
  pitfall_en = 'Using tabs for indentation causes errors (spaces only). Also, indentation misalignment directly becomes structural misalignment, so watch your spacing.'
WHERE id = 'yaml-file';

UPDATE terms SET
  one_liner_en = 'A file that stores secret configuration information',
  definition_en = 'A file that defines environment variables. Stores secret information that must not be made public—API keys, passwords, database connection details, etc.',
  mechanism_en = 'Written in KEY=value format. Applications read this file at startup and use the values as environment variables.',
  analogy_en = 'Important documents in a safe. Keeps information that must not be shown to anyone in a place only the app can read.',
  pitfall_en = 'Never publish this to GitHub! Adding it to .gitignore to prevent upload is an absolute rule.'
WHERE id = 'env-file';

UPDATE terms SET
  one_liner_en = 'An extended format that makes CSS more convenient',
  definition_en = 'Short for Sassy CSS. Extends CSS with convenient features like variables, nesting, and mixins. Ultimately compiled to CSS.',
  mechanism_en = 'Supports variables like $color: blue; and selector nesting. Efficiently manages large stylesheets.',
  analogy_en = 'A "macro-enabled text editor" for CSS. Lets you write common patterns in shorthand and manage values with variables.',
  pitfall_en = 'Browsers can''t read it directly, so compilation to CSS is required. Build tool configuration is needed.'
WHERE id = 'scss-file';

UPDATE terms SET
  one_liner_en = 'A format that lets you write HTML inside JavaScript',
  definition_en = 'Short for JavaScript XML. A syntax extension for describing UI in React. Allows HTML-like notation inside JavaScript code.',
  mechanism_en = 'Lets you write HTML tags directly in JavaScript, like return <div className="card">Hello</div>;. Actually transformed into React function calls.',
  analogy_en = 'A script with dialogue and stage directions together. You can manage "what to display" and "how it behaves" in one place.',
  pitfall_en = 'Use className instead of class, htmlFor instead of for—there are slight differences from HTML rules.'
WHERE id = 'jsx-file';

UPDATE terms SET
  one_liner_en = 'The TypeScript version of JSX',
  definition_en = 'A file format for using JSX syntax in TypeScript. Allows writing React components with type safety. The most commonly used format in modern React development.',
  mechanism_en = 'In addition to JSX features, TypeScript type checking applies. You can define types for props and state, and mistakes are caught as errors.',
  analogy_en = 'JSX with a "quality control officer" attached. It checks your code for mistakes before they happen.',
  pitfall_en = 'Writing type definitions takes extra effort, but the bug-prevention benefit is significant in large projects.'
WHERE id = 'tsx-file';

UPDATE terms SET
  one_liner_en = 'A language for sending commands to databases',
  definition_en = 'Short for Structured Query Language. A language for performing operations on databases—retrieving, adding, updating, and deleting data.',
  mechanism_en = 'Uses English-like syntax to query databases, e.g., SELECT * FROM users WHERE age > 20;',
  analogy_en = 'A request to a librarian. "Please give me a list of members over 20"—you specify conditions for the data you want, and the librarian finds it.',
  pitfall_en = 'SQL injection is an attack method. Directly embedding user input into SQL is dangerous. Always use parameterized queries.'
WHERE id = 'sql-file';

UPDATE terms SET
  one_liner_en = 'The shape or structure of data',
  definition_en = 'A standard that defines how data is structured and represented. File formats (.txt, .json, etc.) are also types of formats.',
  mechanism_en = 'The same information can be expressed in multiple formats—text, JSON, XML, etc. Choose the appropriate format for your purpose.',
  analogy_en = 'Like writing the same address in different ways. The information is the same, but the rules for writing it differ.',
  pitfall_en = '"Format" has another meaning (initialize). "Formatting a hard drive" means erasing all data.'
WHERE id = 'format';

UPDATE terms SET
  one_liner_en = 'Data about data',
  definition_en = 'Not the data itself, but information about the data. Creation date, modification date, author, size, format—these are all metadata.',
  mechanism_en = 'Files carry metadata alongside the main data. Photos may include shooting date, camera model, GPS information, etc.',
  analogy_en = 'A book''s colophon. Not the content of the book itself, but information about the book—"when published," "who wrote it."',
  pitfall_en = 'Photo metadata may contain location data. Check for privacy concerns before uploading to social media.'
WHERE id = 'metadata';

UPDATE terms SET
  one_liner_en = 'Information attached to a file',
  definition_en = 'Information about a file beyond its contents. Includes filename, size, creation date, modification date, access permissions, etc.',
  mechanism_en = 'Managed by the OS in the file system. Check via "Properties" on Windows or "Get Info" on Mac.',
  analogy_en = 'A management sticker on a document. Labels like "Created on…," "Last modified by…," "Size in bytes."',
  pitfall_en = 'When copying a file, the creation date may change to the copy date. Be careful if you need to preserve the original date.'
WHERE id = 'file-metadata';

UPDATE terms SET
  one_liner_en = 'A file that stores application settings',
  definition_en = 'A file that describes application behavior settings. Can be in various formats like JSON, YAML, or .env.',
  mechanism_en = 'Read at application startup; the app behaves according to the settings. You can change behavior by editing the config file without changing code.',
  analogy_en = 'A settings menu on an appliance. Without changing the device itself (program), you can customize behavior just by changing settings.',
  pitfall_en = 'Syntax errors in config files can prevent apps from starting. YAML in particular is strict about indentation.'
WHERE id = 'config-file';

UPDATE terms SET
  one_liner_en = 'Settings or setup',
  definition_en = 'The settings of a system or application, or the act of configuring them. Often abbreviated as "config."',
  mechanism_en = 'Development and production environments often have different configurations. Externalizing settings into files enables flexible operation.',
  analogy_en = 'Car settings. Even with the same car, each driver adjusts seat position, mirror angles, etc.',
  pitfall_en = 'Understand the difference between "configuration" and "hardcoding." Values that may change go in config files; values that never change go in code.'
WHERE id = 'configuration';

UPDATE terms SET
  one_liner_en = 'The combination of technologies used in a project',
  definition_en = 'The combination of technologies (languages, frameworks, tools, etc.) used in application development. Example: React + TypeScript + Tailwind CSS.',
  mechanism_en = 'Technologies are selected for each layer—frontend, backend, database, infrastructure—based on team experience and requirements.',
  analogy_en = 'A recipe and tool set for cooking. Just as "Italian cuisine" has go-to combinations, "web apps" have popular technology sets.',
  pitfall_en = 'Cramming in too many trendy technologies makes things complex. Start simple and add as needed.'
WHERE id = 'tech-stack';

UPDATE terms SET
  one_liner_en = 'A project''s instruction manual',
  definition_en = 'A document file describing a project''s overview, usage, setup instructions, etc. Usually written in Markdown format (README.md).',
  mechanism_en = 'Automatically displayed on a GitHub repository''s top page. Serves as the "entry point" for understanding the project.',
  analogy_en = 'The "Please read this first" sheet included with a product. Reading it tells you what the project is and how to use it.',
  pitfall_en = 'Without a README, others (including your future self) can''t understand the project. Make it a habit to always write one.'
WHERE id = 'readme';

-- ═══════════════════════════════════════
-- Chapter 3: Data Structure Lab (30 terms)
-- ═══════════════════════════════════════

UPDATE terms SET one_liner_en='A sequence of characters—text data', definition_en='A data type consisting of a chain of characters. Expressed by wrapping in quotation marks, like "Hello" or "こんにちは".', mechanism_en='Internally stored as an array of character code values (ASCII or UTF-8). Supports operations like concatenation, splitting, and searching.', analogy_en='A bead necklace. Individual beads (characters) are strung together on a string.', pitfall_en='Numbers can also be strings. "123" is a string, 123 is a number. To calculate, you need to convert to a numeric type.' WHERE id='string';
UPDATE terms SET one_liner_en='Only two values: true or false', definition_en='A data type with only two values: true and false. Used to represent the result of conditional checks.', mechanism_en='The result of a conditional expression is a Boolean. Example: 5 > 3 → true, 5 < 3 → false. Used in if statements.', analogy_en='Yes or No, a switch ON or OFF. An answer to a question with only two possible responses.', pitfall_en='"true" and true are different. The former is a string, the latter is a Boolean.' WHERE id='boolean';
UPDATE terms SET one_liner_en='A number without a decimal point', definition_en='A numeric data type without a fractional part: ..., -2, -1, 0, 1, 2, ...', mechanism_en='Some languages clearly distinguish integers from floating-point numbers. JavaScript unifies them under Number.', analogy_en='The count of apples. You wouldn''t say 1.5 apples—you count 1, 2, 3.', pitfall_en='In JavaScript, integers and decimals are both "Number." However, languages like TypeScript, Java, and Python do distinguish them.' WHERE id='integer';
UPDATE terms SET one_liner_en='Numeric data that can be used in calculations', definition_en='A data type representing numbers—integers, decimals, negatives. Supports arithmetic and comparisons.', mechanism_en='Represented internally in binary. Decimals are stored in floating-point format, which can cause tiny rounding errors.', analogy_en='Numbers you can enter on a calculator. You can add, subtract, and calculate.', pitfall_en='0.1 + 0.2 === 0.3 can be false (floating-point error). Be careful with financial calculations.' WHERE id='number';
UPDATE terms SET one_liner_en='A value representing "intentionally empty"', definition_en='A special value that intentionally indicates "no value exists." Used when you want to set a variable to "nothing."', mechanism_en='Null is an "empty" state explicitly set by the developer. Unlike undefined, it means "intentionally nothing here."', analogy_en='An empty lunchbox. The box (variable) is prepared, but you deliberately left it empty.', pitfall_en='The difference between null and undefined is confusing. Null = "intentionally empty." Undefined = "nothing has been set yet."' WHERE id='null';
UPDATE terms SET one_liner_en='A state meaning "not yet defined"', definition_en='The value when a variable is declared but no value has been assigned, or when accessing a nonexistent property.', mechanism_en='If you write let x; without assigning a value, x becomes undefined.', analogy_en='A package that hasn''t arrived yet. It''s "expected to arrive" but doesn''t exist yet.', pitfall_en='Null is explicit emptiness, undefined is implicit non-definition. Both are falsy, but they''re different under strict equality (===).' WHERE id='undefined';
UPDATE terms SET one_liner_en='An ordered list of data', definition_en='A data structure that stores multiple values in order. Each element is accessed by its index (number).', mechanism_en='Written as [1, 2, 3] or ["apple", "orange", "grape"] with square brackets and comma-separated elements. Indices start at 0.', analogy_en='Numbered lockers. You can retrieve contents by number: locker 0, locker 1, locker 2...', pitfall_en='Indices start at 0. With 3 elements, the last element''s index is 2 (not 3).' WHERE id='array';
UPDATE terms SET one_liner_en='A structure of name-value pairs', definition_en='A data structure holding multiple key (name) and value pairs. Lets you manage related data together.', mechanism_en='Written as { name: "Taro", age: 25 } with curly braces, connecting keys and values with colons.', analogy_en='A business card holder. Information organized with labels like "Name," "Phone number," "Address."', pitfall_en='Arrays and objects are easily confused. Use arrays when order matters, objects when you want to access by name.' WHERE id='object';
UPDATE terms SET one_liner_en='A pair of a name and its data', definition_en='A combination of a key (identifier/name) and its corresponding value. The basic unit of objects and maps.', mechanism_en='In name: "Taro", "name" is the key and "Taro" is the value. Keys must be unique.', analogy_en='A dictionary entry and its definition. "apple (entry): a fruit (definition)"—this kind of correspondence.', pitfall_en='Keys can only be strings (or Symbols). Even if you use a number as a key, it''s internally converted to a string.' WHERE id='key-value-pair';
UPDATE terms SET one_liner_en='A named box for storing data', definition_en='A mechanism for storing a value and accessing it by name. The value can be changed during program execution.', mechanism_en='let x = 10; assigns 10 to variable x. Later, x = 20; changes the value.', analogy_en='A labeled box. Put a fruit in a box labeled "apple," and saying "apple" tells you what''s inside.', pitfall_en='Use meaningful variable names. userName and totalPrice are more readable than x or temp.' WHERE id='variable';
UPDATE terms SET one_liner_en='A box whose value cannot be changed', definition_en='A variable that cannot be reassigned once a value is set. Declared with the const keyword.', mechanism_en='const PI = 3.14159; — attempting PI = 3; afterward causes an error.', analogy_en='An engraved stone tablet. Once carved, it cannot be erased.', pitfall_en='The "contents" of objects and arrays declared with const CAN be modified. Only reassignment is prevented.' WHERE id='constant';
UPDATE terms SET one_liner_en='The category or classification of data', definition_en='A classification representing the nature of data. String, number, boolean, array, object—each is handled differently.', mechanism_en='Available operations vary by type. Strings can be concatenated, numbers calculated, arrays looped over.', analogy_en='Food categories. Vegetables, meat, fish—the cooking method (operation) changes depending on the category.', pitfall_en='JavaScript is a loosely typed language, which makes being mindful of types even more important.' WHERE id='data-type';
UPDATE terms SET one_liner_en='The most basic data types', definition_en='Data types that cannot be decomposed further. JavaScript has 7: string, number, boolean, null, undefined, symbol, bigint.', mechanism_en='Primitive types are copied by value (pass-by-value).', analogy_en='Chemical elements. Hydrogen, oxygen—the basic building blocks that cannot be broken down further.', pitfall_en='Primitives are immutable. "hello"[0] = "H" does not change the original string.' WHERE id='primitive';
UPDATE terms SET one_liner_en='A fixed-length array where order has meaning', definition_en='An array with a fixed number of elements and fixed types per position. Used when position (order) is meaningful.', mechanism_en='const point: [number, number] = [10, 20]; represents x and y coordinates.', analogy_en='Coordinates (x, y) or RGB (red, green, blue)—a set of values where order matters.', pitfall_en='JavaScript doesn''t have a tuple type natively; it''s treated as a regular array. TypeScript can enforce it with types.' WHERE id='tuple';
UPDATE terms SET one_liner_en='A collection of unique values with no duplicates', definition_en='A collection that cannot hold duplicate values. Very fast at checking if a value exists.', mechanism_en='new Set([1, 2, 2, 3]) becomes {1, 2, 3}.', analogy_en='An attendance list. Even if the same person checks in twice, their name only appears once.', pitfall_en='Unlike arrays, you can''t access elements by index.' WHERE id='set';
UPDATE terms SET one_liner_en='Efficient management of key-value pairs', definition_en='A key-value store that can use any type as a key. More flexible and faster than plain objects.', mechanism_en='Created with new Map(). Use set(key, value) to add, get(key) to retrieve.', analogy_en='A phone book. Search by name (key) and find the phone number (value).', pitfall_en='The distinction between objects and Maps can be confusing.' WHERE id='map';
UPDATE terms SET one_liner_en='A mechanism for quickly looking up values by key', definition_en='A data structure that converts keys into numeric values (hash values) for fast storage and retrieval.', mechanism_en='A hash function converts a key into a number, which is used as an array index.', analogy_en='Library bookshelves. A number calculated from the book title determines the shelf location.', pitfall_en='"Hash" has two meanings: cryptographic hash and data structure hash. Context determines the meaning.' WHERE id='hash';
UPDATE terms SET one_liner_en='A number pointing to an element in an array', definition_en='A sequential number assigned to each element of an array. Starts from 0 in most programming languages.', mechanism_en='arr[0] accesses the first element, arr[1] the second.', analogy_en='Apartment room numbers—but starting from room 0.', pitfall_en='The "3rd element" is index 2. Watch out for the gap between human counting (from 1) and programming counting (from 0).' WHERE id='index';
UPDATE terms SET one_liner_en='A blueprint for data structure', definition_en='A specification defining what structure data should have.', mechanism_en='Defines the shape of data in advance: "A user has a name (string) and age (number)."', analogy_en='An application form template. Where to write what is predetermined.', pitfall_en='Making schemas too strict reduces flexibility; too loose degrades data quality.' WHERE id='schema';
UPDATE terms SET one_liner_en='A single entry of data', definition_en='One row in a database, or a data unit combining related fields.', mechanism_en='One row of a users table is one record.', analogy_en='One line in a roster. "Number, name, address, phone number"—one set equals one person''s information.', pitfall_en='TypeScript''s Record<K, V> has a slightly different meaning from a database record.' WHERE id='record';
UPDATE terms SET one_liner_en='A single item within a record', definition_en='A single item or attribute within an object or record.', mechanism_en='In a user record, "name," "age," "email" are each fields.', analogy_en='Input fields on a form. "Name field," "age field," etc.', pitfall_en='Called property, attribute, or member variable depending on context.' WHERE id='field';
UPDATE terms SET one_liner_en='A type that selects from fixed choices', definition_en='An enumeration type. A data type that selects from a predefined, fixed set of values.', mechanism_en='enum Color { Red, Green, Blue } defines it; reference with Color.Red.', analogy_en='A dropdown menu. The selectable options are predetermined.', pitfall_en='TypeScript enums are surprisingly complex. For simple uses, union types may be easier to work with.' WHERE id='enum';
UPDATE terms SET one_liner_en='A type that defines the shape of an object', definition_en='Defines what properties and methods an object should have.', mechanism_en='interface User { name: string; age: number; }', analogy_en='A contract. A promise that "this object will definitely have these things."', pitfall_en='Choosing between interface and type can be confusing.' WHERE id='interface';
UPDATE terms SET one_liner_en='Giving an alternate name to a type', definition_en='A feature for naming complex or frequently-used types for reuse.', mechanism_en='type UserId = string; — give a name to a type and reuse it.', analogy_en='A nickname. Call a long type name by a shorter alias.', pitfall_en='Can do almost the same things as interface, but type alias is better when using union types.' WHERE id='type-alias';
UPDATE terms SET one_liner_en='A type that accepts one of multiple types', definition_en='A type that accepts any of multiple specified types, like "A or B."', mechanism_en='type Status = "success" | "error" | "loading";', analogy_en='Payment options like "cash or card."', pitfall_en='Using union types may require type guards to determine which specific type you have.' WHERE id='union-type';
UPDATE terms SET one_liner_en='A Last-In-First-Out (LIFO) data structure', definition_en='A data structure where the last added element is removed first. Last In, First Out.', mechanism_en='push() adds to the top, pop() removes from the top.', analogy_en='A stack of books. You take the book you placed on top first.', pitfall_en='You can implement a stack with an array, but consciously use only pop() and push().' WHERE id='stack';
UPDATE terms SET one_liner_en='A First-In-First-Out (FIFO) data structure', definition_en='A data structure where the first added element is removed first. First In, First Out.', mechanism_en='enqueue adds to the end, dequeue removes from the front.', analogy_en='A checkout line. The first person in line is served first.', pitfall_en='In JavaScript, shift() and push() can implement a queue, but shift() is slow.' WHERE id='queue';
UPDATE terms SET one_liner_en='A hierarchical structure with parent-child relationships', definition_en='A hierarchical data structure where nodes are connected in parent-child relationships.', mechanism_en='The topmost node is the "root," and nodes without children are "leaves."', analogy_en='A family tree. Grandparents → parents → children → grandchildren branch out.', pitfall_en='Recursive functions are often used for tree processing.' WHERE id='tree';
UPDATE terms SET one_liner_en='A structure representing connections with nodes and edges', definition_en='A data structure composed of nodes (vertices) and edges connecting them.', mechanism_en='Unlike trees, graphs can have cycles (loops).', analogy_en='A subway route map. Stations (nodes) connected by tracks (edges).', pitfall_en='Graph traversal algorithms (BFS, DFS, etc.) can be somewhat challenging.' WHERE id='graph';
UPDATE terms SET one_liner_en='A quantity with direction and magnitude', definition_en='Mathematically, a quantity with direction and magnitude. In programming, represented as a numeric array.', mechanism_en='Represented as [3, 4]. Supports addition, subtraction, scalar multiplication.', analogy_en='An "arrow" on a map. Shows which direction and how far to go.', pitfall_en='Some languages use "Vector" to mean a resizable array.' WHERE id='vector';

-- ═══════════════════════════════════════
-- Chapter 4: Programming Basics (45 terms)
-- Using compact UPDATE format
-- ═══════════════════════════════════════

UPDATE terms SET one_liner_en='Grammar rules of a programming language', definition_en='Rules for how to write a programming language—the order and symbols used to write instructions.', mechanism_en='Code that doesn''t follow syntax rules causes a syntax error and can''t execute. Syntax differs by language.', analogy_en='Language grammar. Japanese follows "subject-object-verb," English follows "subject-verb-object."', pitfall_en='Forgetting semicolons or closing brackets causes errors. Read error messages carefully to locate the issue.' WHERE id='syntax';
UPDATE terms SET one_liner_en='A single unit of executable instruction', definition_en='One unit of instruction in a program. Variable declarations, assignments, conditionals, loops—each is one statement.', mechanism_en='Delimited by semicolons or curly braces, executed top to bottom.', analogy_en='A sentence. Like "I run." or "He eats."—the smallest meaningful instruction unit.', pitfall_en='The difference between expressions and statements is confusing. Expressions return values; statements execute actions.' WHERE id='statement';
UPDATE terms SET one_liner_en='A piece of code that produces a value', definition_en='A code fragment that evaluates to a value. Math formulas, function calls, variable references are all expressions.', mechanism_en='5 + 3 returns 8. x > 10 returns true or false. Expressions are often used as parts of statements.', analogy_en='A math equation. "2 + 3" produces the answer "5" when calculated.', pitfall_en='x = 5 is an assignment statement, but 5 on the right side of = is an expression. Be aware that statements and expressions coexist.' WHERE id='expression';
UPDATE terms SET one_liner_en='Symbols for calculations and comparisons', definition_en='Symbols that perform operations on values. Arithmetic (+, -, *, /), comparison (===, <, >), logical (&&, ||), etc.', mechanism_en='In a + b, + is the operator and a, b are operands. Operators have precedence—* is calculated before +.', analogy_en='Calculator buttons: +, -, ×, ÷. They perform operations on numbers (operands).', pitfall_en='Note the difference between =, ==, and ===. = is assignment, == is loose equality, === is strict equality. Use === in JavaScript.' WHERE id='operator';
UPDATE terms SET one_liner_en='Putting a value into a variable', definition_en='The operation of storing a value in a variable. Uses the = symbol to put the right-hand value into the left-hand variable.', mechanism_en='let x = 10; means "assign 10 to x." x = x + 1; means "reassign x with x plus 1."', analogy_en='Labeling a box and putting something in it. Put an "apple" in the "apple box."', pitfall_en='The = in programming is different from math. It means "put into" not "equals."' WHERE id='assignment';
UPDATE terms SET one_liner_en='Creating a new variable or function', definition_en='Defining a new variable or function. Uses keywords like let, const, function to say "I''m going to use this."', mechanism_en='let x; declares variable x. function greet() {} declares function greet. Usable only after declaration.', analogy_en='Introducing a new employee. "Starting today, this is Mr. Yamada"—only after the announcement can they work.', pitfall_en='Declaration and assignment are separate. let x; is declaration only; let x = 10; is declaration and assignment together.' WHERE id='declaration';
UPDATE terms SET one_liner_en='A named, reusable block of instructions', definition_en='A bundle of instructions given a name that can be called repeatedly. Can receive arguments and return values.', mechanism_en='Defined as function name(params) { code; return result; }. Called with name(). Increases code reusability.', analogy_en='A cooking recipe. Save "how to make curry" as a recipe (function) and you can follow the same steps anytime.', pitfall_en='Functions can call other functions (recursion), but watch out for infinite loops.' WHERE id='function';
UPDATE terms SET one_liner_en='A function that belongs to an object', definition_en='A function defined as a property of an object. Called as object.methodName().', mechanism_en='const obj = { greet: function() { return "Hello"; } }; — call with obj.greet(). Array''s push() and String''s toUpperCase() are also methods.', analogy_en='A person''s skills. "Tanaka.cook()" or "Tanaka.run()"—things that person (object) can do.', pitfall_en='Functions and methods are similar, but methods are always tied to an object. The handling of "this" also differs.' WHERE id='method';
UPDATE terms SET one_liner_en='A placeholder for values a function receives', definition_en='A variable specified at function definition to receive values. Also called a formal parameter.', mechanism_en='In function greet(name) {...}, name is the parameter. Inside the function, use name to access the passed value.', analogy_en='A blank field on an order form. "Name: ___" — the blank (parameter) gets filled with the actual name (argument).', pitfall_en='"Parameter" and "Argument" are easily confused. Parameters are on the definition side; arguments are on the calling side.' WHERE id='parameter';
UPDATE terms SET one_liner_en='Multiple value placeholders for a function', definition_en='When a function receives multiple values, each placeholder. Defined separated by commas.', mechanism_en='In function add(a, b) { return a + b; }, a and b are parameters. Arguments are passed in corresponding order.', analogy_en='Multiple blanks on a form. "Name: ___," "Address: ___," "Phone: ___"—each gets filled in.', pitfall_en='Mismatched argument and parameter counts can cause errors or undefined values.' WHERE id='parameters';
UPDATE terms SET one_liner_en='The actual value passed when calling a function', definition_en='The actual value passed when calling a function. Also called an actual argument.', mechanism_en='In greet("Bit"), "Bit" is the argument. Inside the function, it''s referenced by the parameter name.', analogy_en='What you actually write on the form. Fill in "Taro Yamada" (argument) in the blank (parameter).', pitfall_en='Getting argument order wrong causes unintended behavior. Some languages support named/keyword arguments.' WHERE id='argument';
UPDATE terms SET one_liner_en='The result a function gives back', definition_en='The value returned to the caller as the function''s result. Specified with a return statement.', mechanism_en='function add(a, b) { return a + b; } — add(2, 3) returns 5. Without return, undefined is returned.', analogy_en='Change and product from a vending machine. Put in money (arguments) and get a product (return value) back.', pitfall_en='Forgetting return results in undefined. Also, code after return is never executed.' WHERE id='return-value';
UPDATE terms SET one_liner_en='The range where a variable is visible and accessible', definition_en='The range in which variables can be referenced. Variables outside scope cannot be accessed.', mechanism_en='A variable''s accessible range depends on where it was declared. Variables declared inside a function are invisible from outside.', analogy_en='A school classroom. Only inside the classroom (scope) can you hear the teacher''s voice (variables). It doesn''t reach the next classroom.', pitfall_en='Variables with the same name can exist in different scopes. Be aware of which variable you''re referencing.' WHERE id='scope';
UPDATE terms SET one_liner_en='Visible only inside a function', definition_en='The range where variables declared inside a function are valid. Accessible only within that function.', mechanism_en='function test() { let local = 1; } — local can only be used inside test. Referencing it outside causes an error.', analogy_en='A bookshelf in your room. Books (variables) in your room (function) can''t be reached from outside.', pitfall_en='Local variables are destroyed when the function ends. Use closures to retain them.' WHERE id='local-scope';
UPDATE terms SET one_liner_en='Visible from the entire program', definition_en='The outermost scope accessible from anywhere. Variables declared in global scope can be referenced from anywhere.', mechanism_en='Variables declared outside functions become global. Convenient but carries risk of unintended modifications.', analogy_en='A school announcement. Heard in all classrooms (all scopes). Convenient, but you can''t have private conversations.', pitfall_en='Avoid overusing global variables. They can be changed from anywhere, making them a common source of bugs.' WHERE id='global-scope';
UPDATE terms SET one_liner_en='Visible only within { } braces', definition_en='A scope valid only within a block enclosed by { }. let and const have block scope.', mechanism_en='if (true) { let x = 1; } — x is inaccessible outside the block. var does not have block scope.', analogy_en='A meeting room. Statements (variables) made inside the meeting room (block) aren''t shared outside.', pitfall_en='var doesn''t have block scope, leading to unexpected behavior. Always use let/const.' WHERE id='block-scope';
UPDATE terms SET one_liner_en='A function that remembers outer variables', definition_en='A mechanism where a function "remembers" variables from the scope where it was defined.', mechanism_en='When an inner function references an outer variable, that variable is retained even after the outer function finishes.', analogy_en='A photograph of memories. Even after leaving the place (scope), looking at the photo (closure) recalls the state.', pitfall_en='Excessive closures consume memory. Unintended variable retention can also cause bugs.' WHERE id='closure';
UPDATE terms SET one_liner_en='A function passed to be called later', definition_en='A function passed as an argument to another function, to be called at a specific timing. Common in async and event handling.', mechanism_en='setTimeout(callback, 1000) calls the callback after 1 second. The key is being able to pass functions as values.', analogy_en='"Call me when you''re done." The other party (function) calls you (callback) when their work is finished.', pitfall_en='Deep nesting of callbacks leads to "callback hell." Use Promises or async/await to resolve this.' WHERE id='callback';
UPDATE terms SET one_liner_en='A mechanism to repeat the same process', definition_en='A control structure that repeats the same process while a condition is met. Includes for, while, do-while.', mechanism_en='for (let i = 0; i < 5; i++) { ... } repeats 5 times. Continues until the condition becomes false.', analogy_en='A marathon track. Keep running the same course until you reach the goal (condition).', pitfall_en='Wrong conditions cause infinite loops. Always verify the termination condition.' WHERE id='loop';
UPDATE terms SET one_liner_en='One pass through a loop', definition_en='A single repetition within a loop. 5 loops = 5 iterations.', mechanism_en='Each time a for loop completes one cycle is one iteration.', analogy_en='One lap of a marathon. 10 laps = 10 iterations.', pitfall_en='Getting iteration count wrong means too many or too few operations.' WHERE id='iteration';
UPDATE terms SET one_liner_en='Branching execution based on conditions', definition_en='A control structure that branches which process to execute based on whether a condition is true or false. Includes if and switch.', mechanism_en='if (condition) { true action } else { false action }. Executes different code depending on the condition.', analogy_en='A fork in the road. "If rain, bring umbrella; if sunny, bring sunglasses"—change actions based on the situation.', pitfall_en='Condition order matters. More specific conditions should come first since earlier conditions take priority.' WHERE id='conditional';
UPDATE terms SET one_liner_en='"If this, then that; otherwise, do something else"', definition_en='The most basic conditional syntax. Executes the if block if the condition is true, the else block if false.', mechanism_en='if (score >= 80) { "pass" } else { "fail" }. Multiple conditions possible with else if.', analogy_en='A two-choice quiz. "Correct = ○, Wrong = ×"—the display changes based on the result.', pitfall_en='Forgetting else means nothing happens when the condition isn''t met. Add else as needed.' WHERE id='if-else';
UPDATE terms SET one_liner_en='Branching from multiple choices', definition_en='A conditional syntax that selects and executes from multiple choices based on a variable''s value.', mechanism_en='switch (value) { case "a": ...; break; case "b": ...; break; default: ...; }', analogy_en='Vending machine buttons. Different drinks (actions) come out depending on which button (value) you press.', pitfall_en='Forgetting break causes fall-through to the next case. Always include break unless intentional.' WHERE id='switch-statement';
UPDATE terms SET one_liner_en='A shorthand for if/else in one line', definition_en='An operator in the form condition ? trueValue : falseValue that returns a value based on a condition.', mechanism_en='const result = score >= 80 ? "pass" : "fail";', analogy_en='A ○/× paddle. Show ○ for correct, × for incorrect—a simple two-choice response.', pitfall_en='Complex conditions in ternary operators become hard to read. Use only for simple cases.' WHERE id='ternary-operator';
UPDATE terms SET one_liner_en='Values treated as "true" in conditions', definition_en='Values that become true when converted to Boolean. Everything except false, 0, "", null, undefined, NaN.', mechanism_en='if ("hello") evaluates as true. Non-empty strings, non-zero numbers, and objects are truthy.', analogy_en='A "something is there" state. If the box has anything in it, whatever it is, it counts as "present."', pitfall_en='"0" and "false" are non-empty strings, so they''re truthy. This can be confusing.' WHERE id='truthy';
UPDATE terms SET one_liner_en='Values treated as "false" in conditions', definition_en='Values that become false when converted to Boolean. In JavaScript: false, 0, "", null, undefined, NaN (6 values).', mechanism_en='if (0) evaluates as false. These values are treated as "absent" or "empty" in conditionals.', analogy_en='A "nothing there" state. An empty box, zero dollars, a blank sheet—all count as "absent."', pitfall_en='Empty array [] and empty object {} are NOT falsy—they''re truthy. Check element count instead.' WHERE id='falsy';
UPDATE terms SET one_liner_en='Symbols that compare values and return true/false', definition_en='Operators that compare two values and return true or false. ===, !==, <, >, <=, >=, etc.', mechanism_en='5 === 5 is true, 5 > 3 is true, 5 < 3 is false. Used in conditionals.', analogy_en='A balance scale. Compare two things to see which is heavier (larger, equal).', pitfall_en='== does type coercion, === compares strictly including type. Use === as default.' WHERE id='comparison-operator';
UPDATE terms SET one_liner_en='Symbols for AND, OR, NOT operations', definition_en='Operators for logical operations. && (AND), || (OR), ! (NOT).', mechanism_en='a && b is true only if both are true. a || b is true if either is true. !a flips true/false.', analogy_en='Entry conditions. "18+ AND has ticket" requires both. "Student OR Senior" requires either.', pitfall_en='&& short-circuits: if the first operand is false, the rest isn''t evaluated. This is used as a technique.' WHERE id='logical-operator';
UPDATE terms SET one_liner_en='Joining strings together', definition_en='Combining two or more strings into one. Done with the + operator or template literals.', mechanism_en='"Hello" + " " + "World" becomes "Hello World". Array''s join() also concatenates.', analogy_en='Coupling train cars. Connect cars (strings) to make a longer train (one string).', pitfall_en='Using + with a number and string converts the number to a string. 5 + "3" becomes "53".' WHERE id='concatenation';
UPDATE terms SET one_liner_en='Embedding variables inside a string', definition_en='Inserting variable or expression values into a string. Uses ${variable} inside template literals.', mechanism_en='`Hello, ${name}!` embeds the variable inside backtick-enclosed strings using ${}.', analogy_en='A fill-in-the-blank question. The blank in "My name is (___)" gets automatically filled with the variable''s value.', pitfall_en='Doesn''t work with single or double quotes. Must use backticks (`).' WHERE id='interpolation';
UPDATE terms SET one_liner_en='A string notation that allows variable embedding', definition_en='A string enclosed in backticks (`). Embeds variables and expressions with ${}, and supports multi-line strings.', mechanism_en='`Name: ${name}, Age: ${age}` — multi-line strings are also easy to write.', analogy_en='A template email. An email template where "Dear XX" automatically gets filled in with the name.', pitfall_en='An ES6 feature, so older environments might not support it. Nowadays this is rarely a problem.' WHERE id='template-literal';
UPDATE terms SET one_liner_en='Notes in code that don''t execute', definition_en='Explanatory text written within code. Does not affect program execution. Left as explanations for future self or other developers.', mechanism_en='// for single-line comments, /* */ for multi-line. Used to document intent and caveats.', analogy_en='Notes in the margin of a textbook. Personal memos written next to the main text (code).', pitfall_en='Over-commenting is counterproductive. Make the code itself readable and keep comments minimal.' WHERE id='comment';
UPDATE terms SET one_liner_en='Finding and fixing bugs', definition_en='The work of discovering and fixing program defects (bugs). Uses console.log, debugger tools, etc. to identify causes.', mechanism_en='Techniques include reading error messages, outputting variable values, pausing at breakpoints, etc.', analogy_en='Diagnosing and treating illness. See symptoms (errors), identify the cause (bug), and treat (fix).', pitfall_en='Even if "it works," bugs may remain in other cases. Test various scenarios.' WHERE id='debug';
UPDATE terms SET one_liner_en='A marker that pauses program execution', definition_en='A point where program execution pauses during debugging. Lets you check variable values while paused.', mechanism_en='Set by clicking a line number in dev tools. Execution stops automatically when that line is reached.', analogy_en='Pausing a movie. Stop at an interesting scene to examine the content closely.', pitfall_en='Don''t leave breakpoints in production. Remove debug code before release.' WHERE id='breakpoint';
UPDATE terms SET one_liner_en='An error that occurs during execution', definition_en='An unexpected error situation during program execution. Can be caught and handled with try/catch.', mechanism_en='Occurs when opening a nonexistent file, dividing by zero, accessing properties of undefined, etc.', analogy_en='A mishap while cooking. Like "the pot boiled over!" — you need to handle unexpected situations.', pitfall_en='Ignoring (swallowing) exceptions hides problems. Log appropriately or re-throw.' WHERE id='exception';
UPDATE terms SET one_liner_en='Properly handling errors', definition_en='Implementing mechanisms so programs respond appropriately instead of crashing when errors occur.', mechanism_en='Catch errors with try/catch. Notify users, record logs, perform fallback actions, etc.', analogy_en='Installing emergency exits. Even if a fire (error) breaks out, there''s a safe evacuation (recovery) route.', pitfall_en='Catching and swallowing all errors makes it impossible to find root causes. Handle at appropriate levels.' WHERE id='error-handling';
UPDATE terms SET one_liner_en='A syntax for catching and handling errors', definition_en='A syntax where potentially error-prone code is wrapped in a try block, and errors are handled in a catch block.', mechanism_en='try { risky code } catch (error) { error handling }. Can also use finally for cleanup.', analogy_en='A safety net. Under the trapeze (risky code), a net (catch) catches you if you fall.', pitfall_en='Making the try block too large makes it hard to tell where errors occurred. Keep it minimal.' WHERE id='try-catch';
UPDATE terms SET one_liner_en='A single line of code', definition_en='One line of source code. Error messages reference "error on line X" to indicate location.', mechanism_en='Managed by line numbers shown on the left side of the editor. Important for pinpointing errors.', analogy_en='A book''s page and line. Like "page 32, line 5"—coordinates for locating a position.', pitfall_en='Lines that are too long are hard to read. Break lines appropriately, keeping to 80–120 characters.' WHERE id='line';
UPDATE terms SET one_liner_en='Directives to the computer', definition_en='Specific directives given to a computer to execute. Programs are composed of collections of instructions, executed in sequence.', mechanism_en='Variable declarations, calculations, conditionals, loops—all are instructions to the computer.', analogy_en='Cooking steps. "Chop vegetables," "Put in pot," "Simmer"—a series of specific instructions.', pitfall_en='Wrong instruction order leads to unintended results. Write in logically correct order.' WHERE id='instructions';
UPDATE terms SET one_liner_en='A structure with top-down relationships', definition_en='A structure with parent-child or superior-subordinate relationships. Seen in folder structures, DOM, class inheritance, etc.', mechanism_en='Often represented as tree structures, branching from top to bottom.', analogy_en='A company org chart. CEO → Director → Manager → Employee—a structure with hierarchy.', pitfall_en='Too many levels makes management complex. Keep depth reasonable.' WHERE id='hierarchy';
UPDATE terms SET one_liner_en='Dividing by function for easy reuse', definition_en='A design principle of dividing programs into independent parts (modules) for easier reuse and maintenance.', mechanism_en='Split functionality into separate files and import only what''s needed. Limits the impact of changes.', analogy_en='LEGO blocks. Combine small parts to build large creations. Parts can be reused in other creations.', pitfall_en='Over-dividing creates complexity. Modularize at an appropriate granularity.' WHERE id='modularity';
UPDATE terms SET one_liner_en='How easy code is to read', definition_en='How readable and understandable code is. It''s important that other developers (including your future self) can understand it.', mechanism_en='Good naming, consistent formatting, appropriate comments, and simple structures improve readability.', analogy_en='A neatly written letter. If readable, the content is conveyed correctly.', pitfall_en='It''s tempting to think "if it works, it''s fine." But unreadable code is unmaintainable.' WHERE id='readability';
UPDATE terms SET one_liner_en='The degree of how finely things are divided', definition_en='How finely things are divided. Considered when deciding function or component sizes.', mechanism_en='Finer granularity increases reusability but increases count. Coarser is easier to manage but less flexible.', analogy_en='Sand and rocks. Sand (fine granularity) can change shape freely but there''s lots of it. Rocks (coarse) are easier to handle but have fixed shapes.', pitfall_en='There''s no single right answer for granularity. Decide based on project scale and team preferences.' WHERE id='granularity';
UPDATE terms SET one_liner_en='Writing code directly in place', definition_en='Writing code directly at the spot without separating into functions or modules. Also refers to writing CSS or JS directly in HTML.', mechanism_en='Quick for small tasks but prevents reuse and reduces maintainability.', analogy_en='A disposable tool. Handy on the spot, but if you need the same thing again, you have to make it from scratch.', pitfall_en='Too much inline coding scatters duplicate code everywhere, making fixes painful.' WHERE id='inline-coding';
UPDATE terms SET one_liner_en='Code organized by feature', definition_en='Code organized and divided by feature. Related code is grouped together, making it easy to understand and maintain.', mechanism_en='Organize files and folders by feature—login, search, etc. Makes adding or removing features easier.', analogy_en='An organized closet. "Shirts here," "Pants there"—categorized by type makes things easy to find.', pitfall_en='Whether to organize by technology (controller, view, model) or by feature depends on design philosophy.' WHERE id='feature-aware-code';

-- ═══════════════════════════════════════
-- Chapter 5: HTML & CSS (40 terms)
-- ═══════════════════════════════════════

UPDATE terms SET one_liner_en='A language that builds the skeleton of web pages', definition_en='Short for HyperText Markup Language. A language for describing the structure of web pages. Uses "tags" to wrap elements like headings, paragraphs, links, and images.', mechanism_en='Uses tags like <html>, <body>, <h1>, <p> to define document structure. A browser reads this file and displays it as a web page.', analogy_en='A house blueprint showing "here is a pillar," "here is a wall," "here is a door." HTML indicates "here is a heading," "here is a paragraph," "here is a link."', pitfall_en='HTML alone looks plain. You need CSS for colors and layout. HTML is the "skeleton," CSS is the "interior design."' WHERE id='html';
UPDATE terms SET one_liner_en='A language that styles the appearance of web pages', definition_en='Short for Cascading Style Sheets. A language for specifying visual styles—colors, sizes, layout—for HTML structures.', mechanism_en='Select targets with selectors and specify styles with properties and values. Example: h1 { color: blue; } means "make h1 tags blue."', analogy_en='Interior design for a house. Wallpaper colors, furniture placement, lighting brightness—the role of making everything look beautiful. You can change appearance without changing the structure (HTML).', pitfall_en='CSS''s "C" (Cascading) means later-written styles take priority. Not understanding this "override rule" causes confusion.' WHERE id='css';
UPDATE terms SET one_liner_en='HTML represented as a tree structure', definition_en='Short for Document Object Model. A representation of an HTML document as a tree of objects. Used when JavaScript manipulates a page.', mechanism_en='html → head, body → div, p, h1... nodes are linked in parent-child relationships. Access nodes via document.getElementById() etc.', analogy_en='A family tree. html is the ancestor, branching out to body, div, p and so on.', pitfall_en='DOM manipulation is "expensive." Frequent manipulation slows down the page. This is one reason React uses a virtual DOM.' WHERE id='dom';
UPDATE terms SET one_liner_en='A single HTML component', definition_en='A unit consisting of an opening tag, content, and closing tag. <p>This is a paragraph</p> — the whole thing is one element.', mechanism_en='Elements can be nested. <div><p>Text</p></div> — elements inside elements.', analogy_en='A single LEGO block. Combine blocks (elements) to build larger creations (pages).', pitfall_en='"Tag" and "element" are easily confused. A tag is the <p> or </p> symbol; an element is the entire unit including tags and content.' WHERE id='element';
UPDATE terms SET one_liner_en='Symbols that wrap HTML instructions', definition_en='HTML instructions enclosed in < >. Opening tags <p> and closing tags </p> wrap content to create elements.', mechanism_en='Basic form: <tagname>content</tagname>. Some tags like <img> and <br> have no closing tag ("void elements").', analogy_en='Bookmarks in a book. Markers that show "heading starts here" and "heading ends here."', pitfall_en='Forgetting to close a tag causes layout issues. Always close what you open.' WHERE id='tag';
UPDATE terms SET one_liner_en='Additional information added to a tag', definition_en='Extra information added to a tag, written as attributeName="value" inside the opening tag.', mechanism_en='In <a href="https://example.com">Link</a>, href is the attribute. id, class, src, alt are also attributes.', analogy_en='Labels on a product. Sticking extra info like "Color: red" or "Size: L" on a product (tag).', pitfall_en='Easy to forget the = between attribute name and value, or the quotes around the value. Write precisely.' WHERE id='attribute';
UPDATE terms SET one_liner_en='An attribute that gives the same name to multiple elements', definition_en='An attribute that gives a group name to elements. Multiple elements with the same class name can be styled together.', mechanism_en='<div class="card">...</div> assigns the card class. In CSS, .card { } applies styles. Multiple classes are allowed.', analogy_en='A school class (homeroom). Like "all students in class 1" — you can target an entire group at once.', pitfall_en='Note the difference between class and className. HTML uses class; JSX uses className.' WHERE id='class';
UPDATE terms SET one_liner_en='A unique name given to exactly one element', definition_en='An attribute for identifying a single unique element on a page. The same ID can only be used once per page.', mechanism_en='<div id="main-header">...</div> assigns an ID. In CSS, #main-header { } applies styles.', analogy_en='An employee number. A unique number assigned to one person (one element) within the company (page).', pitfall_en='Using the same ID on multiple elements is invalid. It may work but violates HTML spec and causes bugs.' WHERE id='id';
UPDATE terms SET one_liner_en='A way to choose which elements get styled', definition_en='A notation in CSS that specifies which elements to apply styles to. Can select by tag name, class, ID, attribute, etc.', mechanism_en='div { } selects by tag, .card { } by class, #header { } by ID. Combinations are also possible.', analogy_en='Picking people from a crowd by criteria — "people with red hats" or "people wearing glasses."', pitfall_en='Complex selectors make it hard to tell which elements are targeted. Keep them simple.' WHERE id='selector';
UPDATE terms SET one_liner_en='Specifies what to change in CSS', definition_en='The type of style to change in CSS. color (color), font-size (text size), margin (spacing), etc.', mechanism_en='Written as selector { property: value; }. Example: h1 { color: blue; font-size: 24px; }', analogy_en='Adjustment knob labels. "Volume," "Brightness," "Color" — indicating what to adjust.', pitfall_en='CSS property names use hyphens (font-size). In JavaScript, they become camelCase (fontSize).' WHERE id='property';
UPDATE terms SET one_liner_en='The specific content set for a property', definition_en='The specific value set for a CSS property. Color names, numbers, keywords — available values differ by property.', mechanism_en='In color: blue;, blue is the value. In font-size: 16px;, 16px is the value. In display: flex;, flex is the value.', analogy_en='The actual setting on an adjustment knob. Setting volume to "7" or brightness to "maximum."', pitfall_en='Forgetting units (px, em, rem, %) can cause styles not to apply. Always include appropriate units with numbers.' WHERE id='value';
UPDATE terms SET one_liner_en='Visual appearance settings for elements', definition_en='Settings related to the visual presentation of elements — colors, sizes, fonts, spacing, layout, etc.', mechanism_en='Defined in CSS or directly via HTML''s style attribute. style="color: red;" format.', analogy_en='Clothing coordination. Combining colors, shapes, and materials to create an overall look.', pitfall_en='Inline styles (style attribute) are convenient but reduce maintainability. Avoid overuse.' WHERE id='style';
UPDATE terms SET one_liner_en='A file containing collected styles', definition_en='An external file (.css) containing CSS style definitions. Can be shared across multiple HTML pages.', mechanism_en='Loaded into HTML with <link rel="stylesheet" href="style.css">. Centralizes management of site-wide styles.', analogy_en='A dress code document. A rule book like "suits for meetings" and "casual OK on Fridays."', pitfall_en='Wrong file path means styles won''t apply. Specify paths accurately.' WHERE id='stylesheet';
UPDATE terms SET one_liner_en='Styles written directly on a tag', definition_en='A method of writing CSS directly in an HTML tag''s style attribute. Applies only to that element.', mechanism_en='Written as <p style="color: red; font-size: 16px;">Text</p>.', analogy_en='Quick clothing fix on the spot. Convenient in a hurry, but disorganized and problematic later.', pitfall_en='Not reusable and makes HTML hard to read. Avoid except for emergencies or dynamic JS changes.' WHERE id='inline-style';
UPDATE terms SET one_liner_en='A layout concept treating elements as boxes', definition_en='A CSS layout model where every HTML element is treated as a "box" composed of 4 layers: content, padding, border, and margin.', mechanism_en='From inside out: content → padding (inner spacing) → border (outline) → margin (outer spacing).', analogy_en='A gift box. Contents (content), cushioning (padding), the box itself (border), space around the box (margin).', pitfall_en='Setting width doesn''t include padding and border by default. Use box-sizing: border-box; to fix this.' WHERE id='box-model';
UPDATE terms SET one_liner_en='Outer spacing around an element', definition_en='Spacing created outside an element. Used to adjust the distance between adjacent elements.', mechanism_en='margin: 10px; for all sides. margin: 10px 20px; for top/bottom 10px, left/right 20px. Individual sides also possible.', analogy_en='Personal space between people. Maintaining distance from others (elements).', pitfall_en='Watch out for margin collapse. When vertical margins overlap, only the larger one applies.' WHERE id='margin';
UPDATE terms SET one_liner_en='Inner spacing within an element', definition_en='Spacing inside an element, between the content and border. Background color also applies to the padding area.', mechanism_en='padding: 10px; for all sides. Specification is the same as margin.', analogy_en='Cushioning material inside a box. Inner space that protects the contents (content).', pitfall_en='Increasing padding increases the element''s total size (with box-sizing: content-box;).' WHERE id='padding';
UPDATE terms SET one_liner_en='The outline of an element', definition_en='The outline displayed around an element. Thickness, style, and color can be specified.', mechanism_en='border: 1px solid black; for 1px thick, solid, black outline. border-radius rounds corners.', analogy_en='A picture frame. Surrounds the artwork (content) and adds visual appeal.', pitfall_en='Border is also included in element size (with box-sizing: content-box;). Watch out during layout calculations.' WHERE id='border';
UPDATE terms SET one_liner_en='A property that determines how elements are displayed', definition_en='A CSS property that determines how an element is displayed and participates in layout.', mechanism_en='block stacks vertically, inline flows horizontally, none hides, flex enables flexbox, grid enables grid layout.', analogy_en='Product display methods. "Stack vertically on shelves (block)," "line up horizontally (inline)," "store in warehouse (none)."', pitfall_en='display: none; makes the element disappear entirely. visibility: hidden; hides it but preserves its space.' WHERE id='display';
UPDATE terms SET one_liner_en='A property that determines element positioning', definition_en='A CSS property that determines how an element is positioned. Combined with top, right, bottom, left to specify location.', mechanism_en='static (normal), relative (from original position), absolute (from parent), fixed (from viewport), sticky.', analogy_en='Furniture placement methods. "Follow room flow (static)," "shift from base (relative)," "place freely (absolute)."', pitfall_en='absolute doesn''t work properly if the parent''s position is static. Set the parent to relative.' WHERE id='position';
UPDATE terms SET one_liner_en='A flexible layout method great for one-directional alignment', definition_en='A CSS layout method for flexibly arranging elements in a row or column. Easy to adjust alignment, spacing, and order.', mechanism_en='Set display: flex; on parent. justify-content controls main axis, align-items controls cross axis.', analogy_en='Organizing a bookshelf. Line up books in a row and easily specify "left-aligned," "centered," or "evenly spaced."', pitfall_en='Flexbox is for 1D (row or column). For 2D layouts, Grid is more suitable.' WHERE id='flexbox';
UPDATE terms SET one_liner_en='A layout method great for two-dimensional layouts', definition_en='A CSS layout method for placing elements in a 2D grid of rows and columns. Ideal for complex page layouts.', mechanism_en='Set display: grid; on parent. Define the grid with grid-template-columns and grid-template-rows.', analogy_en='Excel cells. Place elements freely in cells divided by rows and columns.', pitfall_en='Grid is powerful but Flexbox is simpler for basic horizontal alignment. Choose based on the task.' WHERE id='grid';
UPDATE terms SET one_liner_en='A number that determines element stacking order', definition_en='A CSS property that specifies the front-to-back stacking order of positioned elements. Higher values appear in front.', mechanism_en='z-index: 1; appears behind z-index: 10;. Same values follow HTML source order.', analogy_en='Stacking papers. The paper with z-index: 10 goes on top of the one with z-index: 1.', pitfall_en='z-index only compares within the same stacking context. Parent-child relationships may prevent expected results.' WHERE id='z-index';
UPDATE terms SET one_liner_en='Controls how overflowing content is handled', definition_en='A CSS property that specifies how to display content that overflows an element''s box.', mechanism_en='visible (show overflow), hidden (clip), scroll (always scrollbar), auto (scrollbar when needed).', analogy_en='When a cup overflows. "Leave it (visible)," "wipe it up (hidden)," "prepare a saucer (scroll)."', pitfall_en='overflow: hidden; also hides child elements that extend beyond. This can cause unintended layout issues.' WHERE id='overflow';
UPDATE terms SET one_liner_en='The browser''s visible display area', definition_en='The visible area of a browser window where a web page is displayed. Varies by device and screen size.', mechanism_en='Units like vw (viewport width) and vh (viewport height) specify percentages relative to screen size.', analogy_en='The view through a window. The visible range (viewport) changes based on window (browser) size.', pitfall_en='Mobile viewport requires care. Setting the <meta name="viewport"> tag is important.' WHERE id='viewport';
UPDATE terms SET one_liner_en='A technique to adapt design to different screen sizes', definition_en='A web design approach that automatically adjusts layout for various screen sizes — PC, tablet, smartphone.', mechanism_en='Uses media queries to define styles based on screen width. Uses flexible grids and image sizes.', analogy_en='Like water adapting to its container — content transforms to fit the screen size optimally.', pitfall_en='Building mobile-first and expanding for larger screens is often more efficient than shrinking a desktop design.' WHERE id='responsive-design';
UPDATE terms SET one_liner_en='A browser feature to simulate different screen sizes', definition_en='A feature in browser developer tools that lets you check how pages look at various screen sizes without a real device.', mechanism_en='Open dev tools with F12, click the device toolbar. Simulate various devices like iPhone, Pixel, etc.', analogy_en='A fitting room mirror. Check how clothes look (how the page displays) without going outside (without a real device).', pitfall_en='Simulation and real devices may behave differently. Do important checks on actual devices too.' WHERE id='responsive-mode';
UPDATE terms SET one_liner_en='A mechanism to switch styles based on conditions', definition_en='A mechanism that switches applied CSS based on conditions like screen width. The core technology behind responsive design.', mechanism_en='@media (max-width: 768px) { } defines styles for screens 768px and below. min-width, orientation, etc. also available.', analogy_en='Seasonal clothing. "If temperature is below 10°C (condition), wear a coat (style)."', pitfall_en='Breakpoint values should match real devices. 768px, 1024px are commonly used.' WHERE id='media-query';
UPDATE terms SET one_liner_en='An approach of building for mobile first, then expanding', definition_en='An approach where you first design for mobile (smartphone), then add features and layouts as screen size increases.', mechanism_en='Base CSS is mobile-oriented; add larger-screen styles via min-width media queries.', analogy_en='Starting a trip with only essential luggage and adding as needed. More efficient than starting with a full load.', pitfall_en='For existing PC-oriented sites being made mobile-friendly, the reverse approach may be used.' WHERE id='mobile-first';
UPDATE terms SET one_liner_en='HTML that uses meaningful tags', definition_en='HTML that uses tags appropriate to the meaning/role of elements. Uses <header>, <nav>, <main>, <article> instead of <div> everywhere.', mechanism_en='Choose tags matching content meaning. Makes content easier for search engines and screen readers to understand.', analogy_en='A book''s table of contents. Like a TOC showing "Introduction," "Chapter 1," "Summary" — page structure becomes clear.', pitfall_en='<div> and <span> are meaningless tags. Use only for layout; use appropriate tags for meaningful elements.' WHERE id='semantic-html';
UPDATE terms SET one_liner_en='Making websites usable by everyone', definition_en='Ensuring all people can use a website regardless of disabilities or environment. Sometimes abbreviated as a11y.', mechanism_en='Proper contrast, keyboard navigation support, screen reader support, providing alt text, etc.', analogy_en='Barrier-free design. Designing buildings so wheelchair users, visually impaired people — everyone — can use them.', pitfall_en='"Looking pretty" and "being accessible" are different. Stylish low-contrast designs may be hard to read.' WHERE id='accessibility';
UPDATE terms SET one_liner_en='Attributes that convey information to screen readers', definition_en='Short for Accessible Rich Internet Applications. Attributes added to HTML to help assistive technologies (like screen readers) understand content.', mechanism_en='Uses attributes like aria-label, aria-hidden, role. No visual change, but provides information to assistive tech.', analogy_en='An audio guide for visually impaired visitors. Adds descriptions like "there is a button here" and "this is a menu."', pitfall_en='Overusing ARIA can be counterproductive. First use proper semantic HTML; add ARIA only when necessary.' WHERE id='aria';
UPDATE terms SET one_liner_en='Code for embedding external content', definition_en='HTML code for embedding external content like YouTube, Google Maps, or social media posts into your site.', mechanism_en='Copy the "embed code" provided by the service and paste it into HTML. Usually uses iframe.', analogy_en='Like cutting out magazine clippings and pasting them in your scrapbook. Display other services'' content on your site.', pitfall_en='Embedded content can slow page loading. Use only where necessary.' WHERE id='embed-code';
UPDATE terms SET one_liner_en='An element that displays another page within a frame', definition_en='Short for Inline Frame. An element for embedding and displaying another HTML page within an HTML page.', mechanism_en='<iframe src="https://example.com"></iframe> displays an external page. Used for YouTube, Google Maps embeds.', analogy_en='Displaying a different picture inside a picture frame. Creating a "window" to another page within your page''s "room."', pitfall_en='Not all sites allow iframe display for security reasons. May be restricted by X-Frame-Options.' WHERE id='iframe';
UPDATE terms SET one_liner_en='A box that groups elements together', definition_en='A parent element that groups multiple elements together. Used for layout control and applying styles collectively.', mechanism_en='<div class="container">...</div> wraps related elements. Convenient for width control and centering.', analogy_en='A cardboard box. Pack multiple products (elements) into one box (container) for management.', pitfall_en='Avoid deeply nested containers. Keep structure as simple as possible.' WHERE id='container';
UPDATE terms SET one_liner_en='An outer element that wraps other elements', definition_en='An outer element that wraps (encloses) other elements. Often used for the same purposes as a container.', mechanism_en='<div class="wrapper">...</div> wraps elements. The naming is conventional; functionally identical to container.', analogy_en='Gift wrapping paper. Wraps the contents (child elements) to tidy up appearance or group them.', pitfall_en='How to distinguish wrapper from container depends on project conventions. Be consistent.' WHERE id='wrapper';
UPDATE terms SET one_liner_en='An old layout technique that floats elements left or right', definition_en='A CSS property that floats an element left or right, making text wrap around it. Previously used for column layouts.', mechanism_en='float: left; floats left. Following elements wrap around. Use clear to stop wrapping.', analogy_en='A newspaper photo with text. The photo "floats" and text flows around it.', pitfall_en='Using float for layout is deprecated. Use Flexbox or Grid now. Float is still valid for text wrapping around images.' WHERE id='float';
UPDATE terms SET one_liner_en='Stops float wrapping', definition_en='A CSS property that stops float-based text wrapping. Prevents elements from being affected by floated elements.', mechanism_en='clear: both; clears both left and right wrapping. clear: left; or clear: right; clears one side.', analogy_en='A "new paragraph starts here" divider. Cuts off the influence of preceding floated elements.', pitfall_en='The clearfix technique was commonly used. Now overflow: hidden; or display: flow-root; are alternatives.' WHERE id='clear';
UPDATE terms SET one_liner_en='A selector that targets element states', definition_en='A selector that targets specific states of elements (hover, focus, first child, etc.). Starts with one colon (:).', mechanism_en='a:hover (on hover), input:focus (on focus), li:first-child (first child element), etc.', analogy_en='Adjectives describing a person''s state. "Running person" or "Sitting person" — narrowing targets by state.', pitfall_en=':hover is difficult on mobile (requires tap, not hover). Consider touch device support.' WHERE id='pseudo-class';
UPDATE terms SET one_liner_en='A selector that decorates part of an element', definition_en='A selector that targets specific parts of elements (before, after, first letter, first line). Starts with two colons (::).', mechanism_en='p::first-letter (first letter), div::before (before element), div::after (after element), etc.', analogy_en='Highlighting part of a sentence. Decorations like "make the first letter bigger" or "add a symbol after the text."', pitfall_en='::before and ::after require the content property. Even content: ""; must be specified.' WHERE id='pseudo-element';

-- ═══════════════════════════════════════
-- Chapter 6: URL & HTTP (30 terms)
-- ═══════════════════════════════════════

UPDATE terms SET one_liner_en='An address on the internet', definition_en='Short for Uniform Resource Locator. A string that indicates the location of a resource (web page, image, etc.) on the internet.', mechanism_en='Structured as protocol://domain:port/path?query#fragment. Example: https://www.example.com:443/path?name=test#section', analogy_en='A street address. Like "1-2-3 Shibuya, Tokyo" — a string that uniquely identifies a destination.', pitfall_en='URL and URI are technically different (URI is the broader concept), but they''re used almost interchangeably in practice.' WHERE id='url';
UPDATE terms SET one_liner_en='A bridge connecting pages', definition_en='A reference from one web page to another page or resource. Clicking it navigates to a different location.', mechanism_en='Created with HTML''s <a> tag. The href attribute specifies the destination URL. Text or images can be links.', analogy_en='A door. Click to enter another room (page).', pitfall_en='Watch out for broken links (404 errors). Links stop working when destinations are deleted or moved.' WHERE id='link';
UPDATE terms SET one_liner_en='A mechanism to jump to another page with a click', definition_en='A link between documents in hypertext. Clicking navigates to another document or resource.', mechanism_en='A fundamental web mechanism that has existed since HTML''s creation. The origin of the "Web" in World Wide Web.', analogy_en='A warp zone. Click and you can teleport anywhere in the world instantly.', pitfall_en='Link and Hyperlink are used almost interchangeably. Hyperlink is the more formal term.' WHERE id='hyperlink';
UPDATE terms SET one_liner_en='The HTML tag for creating links', definition_en='The <a> tag for creating hyperlinks in HTML. The "a" stands for anchor.', mechanism_en='Used as <a href="https://example.com">Link text</a>. target="_blank" opens in a new tab.', analogy_en='A ship''s anchor. "Anchoring" to a location (URL) and creating a signpost to it.', pitfall_en='When using target="_blank", add rel="noopener noreferrer" for security.' WHERE id='anchor-tag';
UPDATE terms SET one_liner_en='An attribute that specifies the link destination', definition_en='Short for Hypertext Reference. An attribute that specifies the destination URL in <a> and <link> tags.', mechanism_en='Used as <a href="https://example.com">Link</a>. Can use relative or absolute paths.', analogy_en='A directional sign. Like "Tokyo Station this way →" — indicates where to go.', pitfall_en='An empty href or just # causes navigation to the page top. Be careful of unintended behavior.' WHERE id='href';
UPDATE terms SET one_liner_en='A value embedded in the URL path', definition_en='A dynamic value embedded in the path portion of a URL. Used to identify specific resources.', mechanism_en='/users/123 — 123 is the path parameter. APIs often define them as /users/:id using colons.', analogy_en='An apartment room number. "XX Apartments/Room 301" — 301 is the path parameter.', pitfall_en='Path parameters identify resources; query parameters filter/search. Use them appropriately.' WHERE id='path-parameter';
UPDATE terms SET one_liner_en='Information added after the ? in a URL', definition_en='Parameters added at the end of a URL starting with ?, in key=value format. Multiple values are joined with &.', mechanism_en='Format like ?name=test&age=20. Used to pass search criteria, filters, page numbers, etc.', analogy_en='Order options. Like "Ramen? Firm noodles & Extra green onion" — additional conditions with your request.', pitfall_en='Don''t include sensitive information in query strings. URLs are easily logged and visible to others.' WHERE id='query-string';
UPDATE terms SET one_liner_en='A single key=value within a query string', definition_en='An individual parameter within a query string. One key=value pair like name=test.', mechanism_en='In ?name=test&age=20, name=test and age=20 are each query parameters.', analogy_en='One line on an order form. "Name: Yamada" and "Age: 20" are each a query parameter.', pitfall_en='If values contain special characters (&, =, spaces, etc.), URL encoding is required.' WHERE id='query-parameter';
UPDATE terms SET one_liner_en='A human-readable name on the internet', definition_en='A human-readable name like example.com that identifies a computer on the internet.', mechanism_en='A memorable name corresponding to an IP address (a string of numbers). DNS converts it to the actual IP address.', analogy_en='A store name. Call it by "XX Shop" and you can find it without memorizing the address.', pitfall_en='Domains must be purchased and managed. If they expire, someone else can take them.' WHERE id='domain';
UPDATE terms SET one_liner_en='A supplementary name before the domain', definition_en='A name added before the main domain to classify or differentiate sites. www, blog, api are commonly used.', mechanism_en='In blog.example.com, blog is the subdomain. One domain can run multiple services.', analogy_en='Department names. "XX Corp Sales Dept" and "XX Corp Dev Dept" — divisions within the same company.', pitfall_en='www is a type of subdomain. www.example.com and example.com are technically different addresses.' WHERE id='subdomain';
UPDATE terms SET one_liner_en='A system that converts domain names to IP addresses', definition_en='Short for Domain Name System. A system that converts human-readable domain names to computer-readable IP addresses.', mechanism_en='When you enter a URL in a browser, it queries DNS servers to get the IP address, then connects to that server.', analogy_en='A phone book. Search by name (domain) to find the phone number (IP address).', pitfall_en='DNS changes take time to propagate (hours to 48 hours). Understand the concept of TTL (cache time).' WHERE id='dns';
UPDATE terms SET one_liner_en='A computer''s numeric address', definition_en='Short for Internet Protocol address. A string of numbers that identifies a computer on a network.', mechanism_en='IPv4: format like 192.168.1.1 (32-bit). IPv6: format like 2001:0db8:... (128-bit).', analogy_en='A phone number. A sequence of numbers that identifies any computer worldwide.', pitfall_en='Understand the difference between private and public IPs. Home LAN IPs are not visible externally.' WHERE id='ip-address';
UPDATE terms SET one_liner_en='A communication gateway number', definition_en='A number (0–65535) that distinguishes multiple services on a single computer.', mechanism_en='HTTP uses port 80, HTTPS uses 443, dev servers commonly use 3000 or 8080.', analogy_en='Apartment room numbers. Same address (IP) but different room numbers (ports) for different recipients.', pitfall_en='Well-known ports (0-1023) require special privileges. Development typically uses 1024 and above.' WHERE id='port';
UPDATE terms SET one_liner_en='Communication rules for retrieving web pages', definition_en='Short for HyperText Transfer Protocol. A communication protocol for exchanging data between web browsers and servers.', mechanism_en='Client sends a request, server returns a response. Methods include GET, POST, etc.', analogy_en='Letter exchange rules. Like "address goes here" and "stamp goes here" — rules for communication.', pitfall_en='HTTP is not encrypted. Use HTTPS when handling sensitive info like passwords.' WHERE id='http';
UPDATE terms SET one_liner_en='Encrypted HTTP', definition_en='Short for HTTP Secure. HTTP with added encryption (SSL/TLS). Communication content cannot be read by third parties.', mechanism_en='SSL/TLS certificate verifies server identity and encrypts communication. URLs start with https://.', analogy_en='A sealed envelope. A postcard (HTTP) anyone can read, but a sealed letter (HTTPS) requires opening to see contents.', pitfall_en='HTTPS isn''t 100% safe. Phishing sites can also be HTTPS-enabled.' WHERE id='https';
UPDATE terms SET one_liner_en='Technology that encrypts communications', definition_en='Short for Secure Sockets Layer / Transport Layer Security. Security technology that encrypts internet communications.', mechanism_en='Uses public key cryptography to encrypt communications. Certificates prove server identity and prevent man-in-the-middle attacks.', analogy_en='Special ink and dedicated glasses. Letters written in special ink (encryption) can only be read with special glasses (decryption key).', pitfall_en='SSL is old and has vulnerabilities; TLS is now used. However, "SSL certificate" is still commonly said by convention.' WHERE id='ssl-tls';
UPDATE terms SET one_liner_en='Communication rules and agreements', definition_en='Agreements and rules for computers to communicate. Various types exist: HTTP, HTTPS, FTP, SMTP, etc.', mechanism_en='Specifies data format, send/receive procedures, error handling, etc. Communication works when both sides follow the same protocol.', analogy_en='Languages and manners. Japanese speakers use Japanese, English speakers use English — an agreement about how to converse.', pitfall_en='Choose appropriate protocols for each purpose. Web uses HTTP/HTTPS, email uses SMTP/POP3/IMAP, etc.' WHERE id='protocol';
UPDATE terms SET one_liner_en='A request sent to a server', definition_en='A request sent from a client (browser, etc.) to a server. "Give me this page" or "Save this data" type requests.', mechanism_en='Composed of HTTP method (GET, POST, etc.), URL, headers, and body. Server receives it and returns a response.', analogy_en='Ordering at a restaurant. "Curry please" (request) → food arrives (response).', pitfall_en='Use appropriate methods. GET for fetching data, POST for creating, PUT for updating, DELETE for deleting.' WHERE id='request';
UPDATE terms SET one_liner_en='A reply from a server', definition_en='The server''s reply to a client''s request. Composed of status code, headers, and body (data).', mechanism_en='Returns the result of processing the request. 200-series for success, 400-series and 500-series for errors.', analogy_en='Serving food in response to an order. "Here you go" — returning results for a request.', pitfall_en='Slow responses degrade user experience. Understanding the importance of performance optimization is key.' WHERE id='response';
UPDATE terms SET one_liner_en='A 3-digit number indicating the server''s response result', definition_en='A 3-digit number in HTTP responses indicating whether the request succeeded, failed, etc.', mechanism_en='Categorized as 1xx (info), 2xx (success), 3xx (redirect), 4xx (client error), 5xx (server error).', analogy_en='Test scores. "100 points (success)" or "0 points (error)" — results expressed as numbers.', pitfall_en='Understand error code meanings. 404 = "not found," 500 = "server internal error," etc.' WHERE id='status-code';
UPDATE terms SET one_liner_en='Success! No problems', definition_en='An HTTP status code indicating the request was processed successfully. The most basic success response.', mechanism_en='For GET, the requested data is returned. For POST, it means the operation completed successfully.', analogy_en='A "Roger that!" reply. Food arrived as ordered.', pitfall_en='200 doesn''t guarantee the content is what you expected. Make a habit of checking the response body.' WHERE id='200-ok';
UPDATE terms SET one_liner_en='The request was malformed', definition_en='A status code indicating the client''s request has problems. Syntax errors, invalid parameters, etc.', mechanism_en='Occurs due to missing required parameters, invalid JSON format, value format errors, etc.', analogy_en='"Your order was incorrect." Ordering something not on the menu, or an unintelligible request.', pitfall_en='When you get a 400 error, check the request content. Compare against API documentation.' WHERE id='400-bad-request';
UPDATE terms SET one_liner_en='Authentication required', definition_en='A status code indicating authentication info is needed but wasn''t provided or is invalid.', mechanism_en='Occurs when not logged in, token expired, or credentials are wrong.', analogy_en='"Please show your membership card." Entry requires a ticket (auth) but you don''t have one.', pitfall_en='401 vs 403: 401 = "don''t know who you are (no auth)," 403 = "know who you are but denied (no permission)."' WHERE id='401-unauthorized';
UPDATE terms SET one_liner_en='Access denied — no permission', definition_en='A status code indicating the user is authenticated but lacks permission to access the resource.', mechanism_en='Occurs when a regular user tries to access an admin-only page, etc.', analogy_en='"Authorized personnel only." You have ID (auth) but not clearance for that area.', pitfall_en='If you get 403, check permissions. Verify that the required role is assigned.' WHERE id='403-forbidden';
UPDATE terms SET one_liner_en='Page not found', definition_en='A status code indicating the resource at the specified URL doesn''t exist. The most famous error code.', mechanism_en='Occurs from URL typos, deleted/moved pages, broken links, etc.', analogy_en='"Nothing at that address." Visiting a house that was demolished, or a nonexistent address.', pitfall_en='404 pages can be customized. Providing a user-friendly 404 page is a nice touch.' WHERE id='404-not-found';
UPDATE terms SET one_liner_en='Something went wrong on the server side', definition_en='A status code indicating an unexpected error occurred inside the server. A server-side problem.', mechanism_en='Caused by bugs, database connection errors, configuration mistakes, and other server-side issues.', analogy_en='"An accident in the kitchen." The order was correct but the kitchen (server) had a problem and can''t serve.', pitfall_en='500 errors are not the user''s fault. Developers should check server logs to identify the cause.' WHERE id='500-internal-server-error';
UPDATE terms SET one_liner_en='A mechanism to distribute site updates', definition_en='Short for Really Simple Syndication. An XML-format for distributing update information from blogs and news sites.', mechanism_en='RSS readers periodically fetch RSS feeds and display new articles. Manage updates from multiple sites in one place.', analogy_en='Newspaper subscription. Updates come to you without visiting each site individually.', pitfall_en='RSS usage has declined with the rise of social media, but it''s still used for tech blogs and similar sites.' WHERE id='rss';
UPDATE terms SET one_liner_en='A protocol for sending email', definition_en='Short for Simple Mail Transfer Protocol. A communication protocol for sending emails.', mechanism_en='Used to transfer email from client to server and between servers. Receiving uses POP3 or IMAP.', analogy_en='A postal delivery system. Rules for delivering letters (email) to the post office (server). Receiving is a separate system.', pitfall_en='SMTP is for sending only. Use POP3 (download-based) or IMAP (sync-based) for receiving.' WHERE id='smtp';
UPDATE terms SET one_liner_en='Outbound traffic (data going out)', definition_en='Communication or data flowing out from a network to the outside. Sending from server to client, etc.', mechanism_en='Cloud services often charge for egress (outbound) traffic. Can also be controlled with firewalls.', analogy_en='A building exit. The direction of going from inside to outside (data going out).', pitfall_en='Watch egress costs on cloud platforms. Sending large amounts of data can get expensive.' WHERE id='egress';
UPDATE terms SET one_liner_en='Inbound traffic (data coming in)', definition_en='Communication or data flowing from outside into a network. Requests from clients to servers, etc.', mechanism_en='Kubernetes'' Ingress resource controls access from outside the cluster to internal services.', analogy_en='A building entrance. The direction of going from outside to inside (data coming in).', pitfall_en='"Ingress" in Kubernetes is also used as a proper noun. Determine meaning from context.' WHERE id='ingress';

-- ═══════════════════════════════════════
-- Chapter 7: JavaScript & TypeScript (40 terms)
-- ═══════════════════════════════════════

UPDATE terms SET one_liner_en='A programming language that brings web pages to life', definition_en='A programming language that runs in web browsers. Adds interactivity and dynamic features to pages. Also used server-side (Node.js).', mechanism_en='Executed by the browser''s built-in JavaScript engine. Provides DOM manipulation, event handling, async communication, and more.', analogy_en='A house''s electrical system. HTML (structure) and CSS (interior) build the house, then JS adds "press a switch, lights turn on" mechanisms.', pitfall_en='"Java" and "JavaScript" are completely different! Similar names only — different syntax and purposes.' WHERE id='javascript';
UPDATE terms SET one_liner_en='JavaScript made safer with types', definition_en='A language that adds static typing to JavaScript. Developed by Microsoft. Catches errors at compile time, ideal for large-scale development.', mechanism_en='TypeScript code is compiled and converted to JavaScript. Type information is erased at runtime.', analogy_en='A form with defined fields. "Numbers go here," "Text goes here" — defined fields prevent entry mistakes.', pitfall_en='There''s a learning curve, but for large projects, it reduces bugs and ultimately saves time.' WHERE id='typescript';
UPDATE terms SET one_liner_en='JavaScript''s major update (2015)', definition_en='Commonly known as ECMAScript 2015. An important version that added many new features: let/const, arrow functions, classes, modules, etc.', mechanism_en='JavaScript''s standard specification is defined by ECMAScript. Since ES6, new features are added annually.', analogy_en='A major OS update. Like when your phone''s OS got significantly upgraded with many new convenient features.', pitfall_en='Older browsers may not support ES6. Use tools like Babel to transpile for compatibility.' WHERE id='es6';
UPDATE terms SET one_liner_en='JavaScript''s standard specification', definition_en='The standard that defines JavaScript''s language specification. Created by ECMA International. Versions include ES6, ES2020, etc.', mechanism_en='Browser vendors (Google, Mozilla, Apple, etc.) implement JavaScript engines following this specification.', analogy_en='Laws and standards. A rulebook saying "JavaScript should behave this way." Each browser follows it.', pitfall_en='ECMAScript and JavaScript are nearly synonymous, but strictly, ECMAScript is the spec and JavaScript is its implementation.' WHERE id='ecmascript';
UPDATE terms SET one_liner_en='A keyword to declare a reassignable variable', definition_en='A keyword for declaring a block-scoped variable. Its value can be changed later. Introduced in ES6.', mechanism_en='let x = 10; to declare, x = 20; to reassign. Only valid within { } blocks.', analogy_en='A rewritable whiteboard. Write something, erase it, and write something else.', pitfall_en='Don''t use var — use let. var has function scope and tends to cause unintended behavior.' WHERE id='let';
UPDATE terms SET one_liner_en='A keyword to declare an unchangeable constant', definition_en='A keyword for declaring a variable that can''t be reassigned after its initial value. Block-scoped. Introduced in ES6.', mechanism_en='const PI = 3.14; — attempting PI = 3; afterward causes an error.', analogy_en='An engraved stone tablet. Once carved, it can''t be changed. For storing immutable values.', pitfall_en='Objects and arrays declared with const CAN have their contents modified. Only reassignment is prevented.' WHERE id='const';
UPDATE terms SET one_liner_en='A shorter function syntax using =>', definition_en='A shorthand function notation introduced in ES6 using =>. Behaves differently from regular functions regarding "this."', mechanism_en='const add = (a, b) => a + b; — if there''s only one parameter, parentheses can be omitted.', analogy_en='Shorthand writing. Writing the same meaning in shorter symbols. Same content, more compact appearance.', pitfall_en='Arrow functions don''t have their own "this." Be careful when using "this" in event handlers.' WHERE id='arrow-function';
UPDATE terms SET one_liner_en='A keyword that declares an asynchronous function', definition_en='A keyword placed before a function to indicate it performs asynchronous operations. Always returns a Promise.', mechanism_en='async function fetchData() { ... } — inside, you can use await to wait for async operations to complete.', analogy_en='A "Please wait" sign. Declaring in advance that the process will take time.', pitfall_en='An async function''s return value is always a Promise. Even if it looks like a direct return, it''s wrapped in a Promise.' WHERE id='async';
UPDATE terms SET one_liner_en='A keyword that waits for a Promise to resolve', definition_en='A keyword used inside async functions to wait for a Promise to resolve. Lets you write async code that reads like synchronous code.', mechanism_en='const data = await fetch(url); — execution doesn''t proceed to the next line until fetch completes. Catch errors with try/catch.', analogy_en='Just saying "wait." Like waiting for food to arrive — wait until the data comes.', pitfall_en='await can only be used inside async functions. Using it at the top level requires special handling.' WHERE id='await';
UPDATE terms SET one_liner_en='A "promise to deliver results eventually"', definition_en='An object representing the result of an asynchronous operation. Has 3 states: pending, fulfilled (success), rejected (failure).', mechanism_en='Created with new Promise((resolve, reject) => { ... }). Call resolve on success, reject on failure.', analogy_en='A claim ticket. A promise to "deliver the product later." If delivered (fulfilled), collect it; if not (rejected), complain.', pitfall_en='Deep Promise chains become hard to read. Use async/await for better readability.' WHERE id='promise';
UPDATE terms SET one_liner_en='An API for fetching data from servers', definition_en='A Web API for sending HTTP requests and retrieving data. Returns a Promise and works asynchronously.', mechanism_en='fetch(url).then(res => res.json()).then(data => ...) or use with async/await.', analogy_en='Ordering delivery. Call (fetch) and wait for the food (data) to arrive.', pitfall_en='fetch doesn''t reject on HTTP errors (404, 500, etc.). You need to check response.ok.' WHERE id='fetch';
UPDATE terms SET one_liner_en='Methods for handling Promise success and failure', definition_en='Methods for processing Promise results. then() for success, catch() for failure.', mechanism_en='promise.then(result => {...}).catch(error => {...}) — chain them together.', analogy_en='Deciding in advance: "If it works → do this. If it fails → do that."', pitfall_en='Not writing catch swallows errors silently. Always write error handling.' WHERE id='then-catch';
UPDATE terms SET one_liner_en='The "..." that expands arrays and objects', definition_en='An operator using ... to expand array or object elements. Convenient for copying and merging.', mechanism_en='[...arr1, ...arr2] merges arrays. {...obj, newProp: value} adds properties to objects.', analogy_en='Spreading a deck of cards on a table. Expanding a bundle into individual items.', pitfall_en='Spread creates a shallow copy. Nested objects remain as references.' WHERE id='spread-operator';
UPDATE terms SET one_liner_en='Syntax for extracting values from arrays/objects', definition_en='Syntax for concisely assigning elements of arrays or objects to variables. Introduced in ES6.', mechanism_en='const [a, b] = [1, 2]; or const {name, age} = person;', analogy_en='Opening a gift box and placing contents in separate spots. Extract multiple values at once.', pitfall_en='Destructuring a nonexistent property yields undefined. Default values can be set.' WHERE id='destructuring';
UPDATE terms SET one_liner_en='A system for splitting and managing code', definition_en='A system for splitting code into multiple files and loading only what''s needed. Improves reusability and maintainability.', mechanism_en='export to expose, import to load. ES6 modules work in both browsers and Node.js.', analogy_en='LEGO parts. Take out only the parts you need and combine them. No need to keep everything together.', pitfall_en='Watch out for circular references (A imports B, B imports A). May need to rethink the design.' WHERE id='module';
UPDATE terms SET one_liner_en='Loading functionality from another module', definition_en='A keyword for loading exported functions, variables, classes, etc. from another file.', mechanism_en='import { func } from ''./module.js''; or import func from ''./module.js'';', analogy_en='Borrowing books from a library. Borrow the books (functionality) you need for your work.', pitfall_en='Import syntax differs between named exports and default exports.' WHERE id='import';
UPDATE terms SET one_liner_en='Making functionality available to other modules', definition_en='A keyword for exposing functions, variables, classes, etc. from a module. Can be loaded with import.', mechanism_en='export const func = () => {}; or export { func, variable };', analogy_en='Displaying products in a store. Making things available for others (modules) to buy (import).', pitfall_en='Don''t export everything — only expose what external code needs. Be mindful of encapsulation.' WHERE id='export';
UPDATE terms SET one_liner_en='A module''s primary export', definition_en='A single "primary" export per module. Can be imported with any name.', mechanism_en='export default function() {}; — imported as import anyName from ''./module'';', analogy_en='A store''s signature product. The main recommendation. Other products exist, but this is the star.', pitfall_en='Only one default export per module. Can be used alongside named exports.' WHERE id='default-export';
UPDATE terms SET one_liner_en='Exports with specified names', definition_en='A way to export functions and variables with specific names. Must be imported using the same names.', mechanism_en='export { func, variable }; — imported as import { func, variable } from ''./module'';', analogy_en='Products with name tags. "I want this specific named product" — purchased by specifying the name.', pitfall_en='Wrong name during import causes errors. Use "as" to rename if needed.' WHERE id='named-export';
UPDATE terms SET one_liner_en='Re-exporting multiple modules from a single file', definition_en='A pattern of re-exporting multiple modules from a single index.js file. Makes import statements cleaner.', mechanism_en='In index.js: export { a } from ''./a''; export { b } from ''./b''; — external code can import everything from one place.', analogy_en='A reception desk. Consolidating access to various departments (modules) into one point for easier access.', pitfall_en='Overly large barrels can affect tree-shaking performance.' WHERE id='barrel-exports';
UPDATE terms SET one_liner_en='A special variable referring to "itself"', definition_en='A special keyword that references the object that called the function or method.', mechanism_en='What "this" refers to changes based on how it''s called. In a method, it''s the object; called alone, it''s undefined (strict mode).', analogy_en='The word "I." Who "I" refers to depends on who''s speaking.', pitfall_en='Arrow functions don''t have their own "this" — they inherit from the outer scope. Understanding this difference is crucial.' WHERE id='this-keyword';
UPDATE terms SET one_liner_en='User actions or system occurrences', definition_en='Occurrences in the browser — clicks, key presses, mouse movements, etc. JavaScript can detect and process them.', mechanism_en='When an event occurs, an event object is created and passed to registered handlers.', analogy_en='A doorbell. When someone rings the bell (event occurs), you go greet them (process it).', pitfall_en='There are many event types. click, change, submit, keydown, load — choose based on purpose.' WHERE id='event';
UPDATE terms SET one_liner_en='A mechanism that "listens" for events', definition_en='A mechanism that registers a function to execute when a specific event occurs.', mechanism_en='Register with element.addEventListener(''click'', handler). Remove with removeEventListener.', analogy_en='A lookout. You ask "Tell me when it''s clicked." When it happens, they report back.', pitfall_en='Remove listeners when no longer needed. They can cause memory leaks if left registered.' WHERE id='event-listener';
UPDATE terms SET one_liner_en='A function executed when an event occurs', definition_en='A function called when an event fires. Receives the event object as an argument.', mechanism_en='Defined as function handleClick(event) { ... } and registered with addEventListener.', analogy_en='An emergency response manual. A procedure guide for "when this happens, do this."', pitfall_en='Heavy processing in handlers blocks the UI. Use async processing when necessary.' WHERE id='event-handler';
UPDATE terms SET one_liner_en='Stops the browser''s default behavior', definition_en='A method that disables default actions for events (link navigation, form submission, etc.).', mechanism_en='Call event.preventDefault() inside the handler. Prevents page reload on form submit, etc.', analogy_en='"Please skip the usual routine." Like stopping an automatic door from opening.', pitfall_en='Use only when needed. Overuse disrupts expected user behavior.' WHERE id='prevent-default';
UPDATE terms SET one_liner_en='Execute once after a specified delay', definition_en='A timer function that executes a function once after a specified number of milliseconds.', mechanism_en='setTimeout(callback, 1000) executes callback after 1 second. Cancel with clearTimeout.', analogy_en='An alarm. Set to "wake me in 5 minutes" — it rings once after 5 minutes.', pitfall_en='Timing isn''t guaranteed (at minimum the specified time). Not suitable for processes requiring precise timing.' WHERE id='settimeout';
UPDATE terms SET one_liner_en='Execute repeatedly at specified intervals', definition_en='A timer function that repeatedly executes a function at specified millisecond intervals.', mechanism_en='setInterval(callback, 1000) executes callback every second. Stop with clearInterval.', analogy_en='An alarm clock''s snooze feature. It rings repeatedly at intervals until you stop it.', pitfall_en='Intervals can persist after component unmount. Don''t forget cleanup.' WHERE id='setinterval';
UPDATE terms SET one_liner_en='Transform each array element into a new array', definition_en='A method that applies a function to each array element and creates a new array from the results.', mechanism_en='[1, 2, 3].map(x => x * 2) returns [2, 4, 6]. The original array is not modified.', analogy_en='A factory line. Each raw material (element) is processed (transformed) one by one into new products (array).', pitfall_en='map returns a new array. If you don''t need the return value, use forEach instead.' WHERE id='map-function';
UPDATE terms SET one_liner_en='Extract only elements matching a condition', definition_en='A method that tests each array element against a condition and creates a new array of only matching elements.', mechanism_en='[1, 2, 3, 4].filter(x => x > 2) returns [3, 4]. The original array is not modified.', analogy_en='A sieve. Only items meeting the size criteria pass through; the rest fall away.', pitfall_en='Returns an empty array (not an error) if no elements match.' WHERE id='filter-function';
UPDATE terms SET one_liner_en='Combine an array into a single value', definition_en='A method that processes array elements sequentially and combines them into a single value (sum, object, array, etc.).', mechanism_en='[1, 2, 3].reduce((acc, cur) => acc + cur, 0) returns 6. Initial value is the second argument.', analogy_en='Making a snowball. Each roll adds more snow (elements), eventually forming one big snowball (result).', pitfall_en='Omitting the initial value uses the first element. Empty arrays cause errors — be careful.' WHERE id='reduce-function';
UPDATE terms SET one_liner_en='Execute a process on each array element', definition_en='A method that executes a specified function on each array element. No return value — used for side effects.', mechanism_en='[1, 2, 3].forEach(x => console.log(x)) outputs each element. Unlike map, it doesn''t create a new array.', analogy_en='Roll call. Calling each name one by one to check. Not creating a new list of results.', pitfall_en='forEach can''t break early (no break). Use for...of if you need to exit mid-loop.' WHERE id='foreach';
UPDATE terms SET one_liner_en='Get the first element matching a condition', definition_en='A method that returns the first element in an array that satisfies a condition. Returns undefined if not found.', mechanism_en='[1, 2, 3].find(x => x > 1) returns 2. Search stops at the first match.', analogy_en='Looking for a lost item. Once you find something matching the criteria, search is over.', pitfall_en='Handle the undefined case when nothing is found. Use optional chaining or conditional checks.' WHERE id='find';
UPDATE terms SET one_liner_en='Output values to the developer tools', definition_en='A method that outputs messages and values to the browser''s developer tools (console). Essential for debugging.', mechanism_en='console.log(''Hello''); or console.log(variable); to inspect values.', analogy_en='Recording mental notes. Writing out a program''s progress in a way only you can see.', pitfall_en='Don''t leave console.log in production. Remove debug logs or manage log levels.' WHERE id='console-log';
UPDATE terms SET one_liner_en='A method that runs when accessing a property', definition_en='A getter method that automatically runs when an object''s property is accessed.', mechanism_en='get propName() { return this._prop; } — accessing obj.propName triggers the getter.', analogy_en='An automatic door. Just approaching (accessing) triggers the door to open (processing to execute) automatically.', pitfall_en='Heavy processing in getters impacts performance on every property access.' WHERE id='get';
UPDATE terms SET one_liner_en='An operator that checks a value''s type', definition_en='An operator that returns a value''s data type as a string. Returns ''string'', ''number'', ''boolean'', ''object'', etc.', mechanism_en='typeof 42 returns ''number''. typeof ''hello'' returns ''string''.', analogy_en='Material appraisal. "This is wood" or "This is metal" — identifying the material (type).', pitfall_en='typeof null returns ''object'' (a historical JavaScript bug). Use === null for null checks.' WHERE id='typeof';
UPDATE terms SET one_liner_en='A JavaScript runtime for servers', definition_en='An environment for running JavaScript outside the browser. Used for server-side development, CLI tools, build tools, etc.', mechanism_en='Uses the V8 engine (same as Chrome). Manages libraries with npm (package manager).', analogy_en='JavaScript on a business trip. Left the browser workplace and can now work on servers too.', pitfall_en='Browser APIs (window, document, etc.) are unavailable in Node.js. Be aware of environment differences.' WHERE id='node-js';
UPDATE terms SET one_liner_en='A type validation library for TypeScript', definition_en='A TypeScript-oriented library for validating data types at runtime. Used for API response and form input validation.', mechanism_en='z.object({ name: z.string() }).parse(data) validates data. Throws an exception if invalid.', analogy_en='An immigration officer. "Is your passport (type) correct?" — checks and denies entry if invalid.', pitfall_en='TypeScript types are erased at runtime. Zod''s strength is that it can also type-check at runtime.' WHERE id='zod';
UPDATE terms SET one_liner_en='Importing an external library', definition_en='Importing an external library installed via npm etc. into your code for use.', mechanism_en='import React from ''react''; — import by specifying the package name.', analogy_en='Borrowing tools. Use convenient tools (libraries) someone else made without building them yourself.', pitfall_en='Watch out for bundle size growing too large. Import only the functionality you need.' WHERE id='library-import';
UPDATE terms SET one_liner_en='Versatile, reusable helper functions', definition_en='General-purpose functions usable in various situations, not tied to specific features. Date formatting, array manipulation, etc. are typical.', mechanism_en='Often organized in a utils/ folder. Libraries like lodash are representative utility libraries.', analogy_en='A Swiss army knife. A highly versatile tool useful in many situations.', pitfall_en='"Utility" folders tend to grow bloated. Organize by grouping related functions into separate files.' WHERE id='utility';
UPDATE terms SET one_liner_en='Analyzing strings to convert into structured data', definition_en='Analyzing a string and converting it into a format programs can easily handle (objects, numbers, etc.).', mechanism_en='JSON.parse(jsonString) converts a JSON string to an object. parseInt(''42'') converts a string to a number.', analogy_en='Translation. Converting a foreign language (string) into your native language (structured data) for comprehension.', pitfall_en='Parsing invalid JSON strings causes errors. Use try/catch for error handling.' WHERE id='parsing';

-- ═══════════════════════════════════════
-- Chapter 16: API - The Embassy (45 terms)
-- ═══════════════════════════════════════

UPDATE terms SET one_liner_en='An HTTP method for deleting data', definition_en='An HTTP method that deletes a specified resource. DELETE /users/123 deletes the user with ID 123.', mechanism_en='An idempotent operation — sending the same request multiple times yields the same result (already deleted stays deleted).', analogy_en='Removing a book from a library. Taking an unneeded book off the shelf.', pitfall_en='Deletion is irreversible. Consider using soft deletes (deleted_at flag) as an alternative.' WHERE id='delete';
UPDATE terms SET one_liner_en='The 4 fundamental data operations', definition_en='Acronym for Create, Read, Update, Delete. The basic pattern for data operations.', mechanism_en='Maps to POST (Create), GET (Read), PUT/PATCH (Update), DELETE (Delete).', analogy_en='How you use a notebook. Write (Create), read (Read), rewrite (Update), erase (Delete).', pitfall_en='Not all APIs fit neatly into CRUD. Action-oriented operations may need different designs.' WHERE id='crud';
UPDATE terms SET one_liner_en='Types of HTTP request operations', definition_en='Types of operations in HTTP requests. GET, POST, PUT, PATCH, DELETE, HEAD, OPTIONS, etc.', mechanism_en='Combined with URLs to express operations on resources. GET /users means "fetch user list."', analogy_en='Verbs. After "the book," you add "read," "write," "delete" — words indicating what to do.', pitfall_en='Use the right methods. Avoid improper usage like fetching data with POST.' WHERE id='http-methods';
UPDATE terms SET one_liner_en='A communication interface between systems', definition_en='Short for Application Programming Interface. Rules and gateways for different software to communicate.', mechanism_en='Send a request, get a response in a defined format. Comes in forms like REST API, GraphQL API.', analogy_en='An embassy counter. An official gateway for interacting with a foreign country (another system).', pitfall_en='API spec changes affect clients. Manage compatibility with versioning.' WHERE id='api';
UPDATE terms SET one_liner_en='An authentication key for API usage', definition_en='An authentication string required when using an API. Identifies who''s using the API for access control and billing.', mechanism_en='Sent in request headers or query parameters. Validated on the server for authentication.', analogy_en='A building pass. Without this pass (key), you can''t enter the building (API).', pitfall_en='Never expose API keys. Don''t push to GitHub, don''t embed in frontend code.' WHERE id='api-key';
UPDATE terms SET one_liner_en='Sending a request to an API', definition_en='The action of sending an HTTP request to an API endpoint and receiving a response.', mechanism_en='Send requests with fetch() or axios. Executes asynchronously, receiving responses via Promise.', analogy_en='Making a phone call. Call the other party (API), wait for their reply (response).', pitfall_en='API calls can fail. Always implement error handling.' WHERE id='api-call';
UPDATE terms SET one_liner_en='A URL for accessing a specific API function', definition_en='A URL for accessing a specific function or resource provided by an API. Like https://api.example.com/users.', mechanism_en='Composed of base URL + path. Combined with HTTP methods to identify the function.', analogy_en='Specific counters in an embassy. "Visa applications here," "Inquiries there" — separate windows for different services.', pitfall_en='Keep endpoint design consistent. Unify naming conventions.' WHERE id='api-endpoint';
UPDATE terms SET one_liner_en='An API following REST principles', definition_en='An API designed following the REST architectural style. The most common form, using HTTP methods and URLs to operate on resources.', mechanism_en='Resources are represented by URLs and manipulated with HTTP methods. Data is typically exchanged in JSON.', analogy_en='An international standard diplomatic protocol. Conducting diplomacy following worldwide common rules.', pitfall_en='It doesn''t need to be perfectly RESTful. Prioritize practicality in design.' WHERE id='rest-api';
UPDATE terms SET one_liner_en='A query language for fetching only the data you need', definition_en='A query language for APIs developed by Facebook. Clients specify the shape of the data they need.', mechanism_en='Send queries to a single endpoint. Specify desired fields to get exactly the right amount of data.', analogy_en='Made-to-order. "Give me only this part and that part" — fine-grained specification.', pitfall_en='Has a learning curve. For simple APIs, REST API is often sufficient.' WHERE id='graphql';
UPDATE terms SET one_liner_en='A request to retrieve data', definition_en='A request to retrieve data from a database or API. In GraphQL, it refers to data-fetching operations.', mechanism_en='In GraphQL: query { user { name } }. In SQL, it corresponds to SELECT statements.', analogy_en='A question. "Please tell me this" — inquiring for data.', pitfall_en='Complex queries affect performance. Watch out for issues like N+1 problems.' WHERE id='query';
UPDATE terms SET one_liner_en='An operation to change data in GraphQL', definition_en='An operation in GraphQL for creating, updating, or deleting data. Equivalent to REST''s POST, PUT, DELETE.', mechanism_en='mutation { createUser(name: "Taro") { id } } format.', analogy_en='An application form. A request to "please change this" or "please register this."', pitfall_en='All operations with side effects should be Mutations. Queries should not change data.' WHERE id='mutation';
UPDATE terms SET one_liner_en='A protocol for bidirectional real-time communication', definition_en='A protocol for bidirectional real-time communication between client and server. Used for chat and games.', mechanism_en='Once a connection is established, the server can also push to the client. Maintains a persistent connection.', analogy_en='A phone line. Once connected, either side can speak at any time. HTTP is like letter exchange.', pitfall_en='Maintaining connections consumes resources. Use only where necessary.' WHERE id='websocket';
UPDATE terms SET one_liner_en='A connection point for network communication', definition_en='An abstract connection point for network communication. A "plug" for sending and receiving data.', mechanism_en='Identified by IP address and port number. Sends and receives data over TCP/UDP.', analogy_en='An electrical outlet. Plug in to start data flowing.', pitfall_en='Libraries like Socket.io make implementation easier. Raw sockets are harder to work with.' WHERE id='socket';
UPDATE terms SET one_liner_en='Communication or processing that reflects instantly', definition_en='Communication or processing where data is reflected without delay. Needed for chat, stock prices, online games, etc.', mechanism_en='Achieved with WebSocket, Server-Sent Events, polling, etc. Choose based on use case.', analogy_en='A live broadcast. Not recorded (batch processing) — what''s happening now arrives immediately.', pitfall_en='Real-time is resource-intensive. Consider whether you truly need it.' WHERE id='real-time';
UPDATE terms SET one_liner_en='A mechanism to automatically receive changes', definition_en='A mechanism in GraphQL for receiving server-side changes in real-time. Clients are notified automatically when data updates.', mechanism_en='Implemented via WebSocket. Defined as subscription { messageAdded { content } }.', analogy_en='Newspaper subscription. When a new article (data) comes out, it''s automatically delivered to you.', pitfall_en='Leaving subscriptions active consumes resources. Unsubscribe when no longer needed.' WHERE id='real-time-subscription';
UPDATE terms SET one_liner_en='A mechanism that sends notifications when events occur', definition_en='A mechanism that automatically sends HTTP requests to a specified URL when specific events occur. Also called reverse API or HTTP callback.', mechanism_en='When events like payment completion, commits, or form submissions occur, a POST request is sent to the registered URL.', analogy_en='Event-triggered phone calls. "Call me when payment is complete" — you set it up in advance.', pitfall_en='Implement authentication on the webhook receiver. Prevent fake requests.' WHERE id='webhook';
UPDATE terms SET one_liner_en='A function called after processing completes', definition_en='A function executed after some processing finishes. Used to receive results of asynchronous operations.', mechanism_en='Pass a function as an argument to be called upon completion. Like fetchData(data => console.log(data)).', analogy_en='"Call me when you''re done." You get a callback phone call when the task is finished.', pitfall_en='Watch out for callback hell. If nesting gets deep, use Promises or async/await.' WHERE id='callback';
UPDATE terms SET one_liner_en='An ID for identifying callbacks', definition_en='A unique identifier for distinguishing among multiple callback operations. Used to identify which request a response belongs to.', mechanism_en='An ID is assigned at request time and returned in the response. Used for tracking async operations.', analogy_en='A ticket number. "Number 123, please" — you know it''s your turn.', pitfall_en='IDs must be guaranteed unique. Using UUIDs is safe.' WHERE id='callback-id';
UPDATE terms SET one_liner_en='Calling a function or API', definition_en='The act of executing a function or API. Also used when counting Lambda function executions.', mechanism_en='The act of calling a function. The () in myFunction() performs the invocation.', analogy_en='Summoning. Casting a spell (function) to activate its effect.', pitfall_en='Serverless often charges per invocation. Avoid unnecessary calls.' WHERE id='invocation';
UPDATE terms SET one_liner_en='A limit on API call frequency', definition_en='A cap on how many times an API can be called within a given time period. Prevents server overload and enforces plan limits.', mechanism_en='E.g., 60 per minute or 1000 per day. Exceeding returns HTTP 429 (Too Many Requests).', analogy_en='Entry restrictions. "100 people per hour" to prevent overcrowding.', pitfall_en='When you hit a rate limit, space out retries. Exponential backoff is standard.' WHERE id='rate-limit';
UPDATE terms SET one_liner_en='Intentionally limiting processing speed', definition_en='Intentionally limiting the rate of request processing. Used for server protection and API usage control.', mechanism_en='Executes processing only at fixed intervals. Excess requests are queued or rejected.', analogy_en='Turning down a faucet. Restricting the flow of water (requests) to prevent overflow.', pitfall_en='Don''t confuse throttle with debounce. Throttle executes at intervals; debounce executes only the last one.' WHERE id='throttling';
UPDATE terms SET one_liner_en='Consolidating rapid successive calls into one', definition_en='A technique that groups rapidly successive events and processes only the last one. Used for optimizing search input, etc.', mechanism_en='After an event fires, wait a set time before executing. If a new event fires during the wait, reset the timer.', analogy_en='An elevator door. Waits as people keep boarding. Closes once things settle down.', pitfall_en='Too long a wait degrades responsiveness. Set an appropriate time (around 300ms).' WHERE id='debouncing';
UPDATE terms SET one_liner_en='Interrupting a process that exceeds the time limit', definition_en='Interrupting a process when no response is received within a set time. Prevents waiting indefinitely.', mechanism_en='Set a timeout duration on requests. If no response comes in time, treat it as an error.', analogy_en='A meeting time limit. Wait 30 minutes; if they don''t come, stop waiting.', pitfall_en='Too short a timeout causes normal requests to fail. Set an appropriate duration.' WHERE id='timeout';
UPDATE terms SET one_liner_en='A mechanism allowing cross-origin communication', definition_en='Short for Cross-Origin Resource Sharing. A mechanism that allows browser communication between different origins (domains), which is normally blocked for security.', mechanism_en='The server specifies allowed origins with the Access-Control-Allow-Origin header.', analogy_en='An entry permit. Declaring "visitors from this country (origin) are accepted."', pitfall_en='"CORS errors" are common during development. Resolved with server-side configuration.' WHERE id='cors';
UPDATE terms SET one_liner_en='A development support toolkit', definition_en='Short for Software Development Kit. A set of dev tools, libraries, and documentation for a specific service or platform.', mechanism_en='Instead of calling APIs directly, just call SDK functions. Authentication is also simplified.', analogy_en='A cooking kit. Ingredients, seasonings, and recipe included — easy to cook (develop).', pitfall_en='Keep up with SDK version updates. Outdated SDKs can be security risks.' WHERE id='sdk';
UPDATE terms SET one_liner_en='Verifying "who you are"', definition_en='The process of confirming a user''s identity. Uses passwords, biometrics, tokens, etc. for identity verification.', mechanism_en='Credentials are validated at login. On success, a session or token is issued.', analogy_en='Passport check. Confirming "are you really Mr./Ms. XX?"', pitfall_en='Authentication and authorization are different. Authentication = "who are you"; authorization = "what can you do."' WHERE id='authentication';
UPDATE terms SET one_liner_en='Checking "what you can do"', definition_en='The process of checking whether an authenticated user has permission to access specific resources or actions.', mechanism_en='Checks roles (admin, user, etc.) and permissions. Returns 403 error if unauthorized.', analogy_en='An area access pass. Even with a passport (authentication), VIP areas require separate clearance.', pitfall_en='Always perform authorization checks server-side. Frontend-only checks are insufficient.' WHERE id='authorization';
UPDATE terms SET one_liner_en='A string representing authentication info', definition_en='An encrypted string representing a user''s authentication information. JWT is common. Attached to requests for server verification.', mechanism_en='Issued on successful login. Included in the Authorization header of subsequent requests.', analogy_en='A pass. With this pass, you can get through without showing your passport (logging in) each time.', pitfall_en='Set appropriate token expiration. Too long is a security risk; too short is inconvenient.' WHERE id='token';
UPDATE terms SET one_liner_en='A JSON-based token format', definition_en='Short for JSON Web Token. A self-contained token format consisting of header, payload, and signature.', mechanism_en='Three Base64-encoded parts joined by dots. Signature enables tamper detection.', analogy_en='A sealed letter. Contents (payload) plus a seal (signature) that reveals if it''s been opened.', pitfall_en='Payload is NOT encrypted. Don''t put sensitive info in it. Signature is for verification only.' WHERE id='jwt';
UPDATE terms SET one_liner_en='A mechanism for delegating permissions to another service', definition_en='An authorization framework for users to safely share their info with other services. Used for "Login with Google" etc.', mechanism_en='User grants permission → authorization code obtained → access token obtained → API access.', analogy_en='Power of attorney. "I grant this service permission to do this on my behalf."', pitfall_en='OAuth is authorization, not authentication. Combine with OpenID Connect for authentication.' WHERE id='oauth';
UPDATE terms SET one_liner_en='A lightweight format for data exchange', definition_en='Short for JavaScript Object Notation. A data exchange format readable by both humans and machines. The standard API format.', mechanism_en='{ "key": "value" } format. Expresses arrays, objects, strings, numbers, booleans, and null.', analogy_en='A common language. A data format understood by any country (programming language).', pitfall_en='JSON keys must be in double quotes. Single quotes or unquoted keys cause errors.' WHERE id='json';
UPDATE terms SET one_liner_en='A tag-based data format', definition_en='Short for Extensible Markup Language. A tag-based structured data format. Used in older APIs (SOAP) and config files.', mechanism_en='<tag>content</tag> format. Attributes are also supported. Similar to HTML but with stricter rules.', analogy_en='An official document. A formal format with strict structural rules.', pitfall_en='More verbose and harder to handle than JSON. JSON is mainstream for new development.' WHERE id='xml';
UPDATE terms SET one_liner_en='Converting data into a transmittable format', definition_en='Converting objects and data structures into a format that can be stored or transmitted (JSON, strings, etc.).', mechanism_en='JSON.stringify() converts an object to a JSON string. The reverse is deserialization.', analogy_en='Packing for shipping. Packaging complex shapes (objects) into a shippable form (strings).', pitfall_en='Circular references can''t be serialized. Watch your data structure.' WHERE id='serialization';
UPDATE terms SET one_liner_en='Restoring strings back into data', definition_en='Restoring serialized strings back into their original objects or data structures.', mechanism_en='JSON.parse() converts a JSON string back to an object. Used for processing API responses, etc.', analogy_en='Unpacking. Opening delivered packages (strings) and taking out the contents (objects).', pitfall_en='Deserializing untrusted data is a security risk. Validate first.' WHERE id='deserialization';
UPDATE terms SET one_liner_en='Temporarily storing data for faster access', definition_en='A mechanism for temporarily storing frequently accessed data to speed up subsequent access.', mechanism_en='Implemented at multiple layers: browser cache, CDN, server cache.', analogy_en='Keeping frequently used books on your desk. No need to go to the bookshelf (database) — they''re right at hand.', pitfall_en='Stale cache means outdated data. An appropriate caching strategy is essential.' WHERE id='cache';
UPDATE terms SET one_liner_en='A network that delivers content worldwide', definition_en='Short for Content Delivery Network. Servers placed worldwide deliver content from the location closest to the user.', mechanism_en='Origin server content is cached on edge servers. Delivered from the nearest server.', analogy_en='A convenience store chain. Pick up headquarters'' (origin) products at your nearest store (edge).', pitfall_en='Be careful caching dynamic content. Ensure user-specific data doesn''t get cached.' WHERE id='cdn';
UPDATE terms SET one_liner_en='Communication delay time', definition_en='The delay between sending a request and receiving a response. Measured in milliseconds (ms).', mechanism_en='Affected by network distance, server processing time, data size, etc. Can be reduced with CDN.', analogy_en='Time lag on a phone call. Like the slight delay when making international calls.', pitfall_en='Latency can''t be zero. Aim to optimize to a level that doesn''t impact user experience.' WHERE id='latency';
UPDATE terms SET one_liner_en='Distributing load across multiple servers', definition_en='A mechanism that distributes requests across multiple servers to prevent any single one from being overloaded.', mechanism_en='A load balancer distributes requests. Algorithms include round-robin, least connections, etc.', analogy_en='Bank queue numbers. Distributing people across multiple counters to equalize wait times.', pitfall_en='Watch session management. Design so users work correctly even when routed to different servers.' WHERE id='load-balancing';
UPDATE terms SET one_liner_en='Fetching large data in divided pages', definition_en='A mechanism where APIs return large datasets in page-sized chunks rather than all at once. Balances performance and usability.', mechanism_en='Controlled with limit (count) and offset (start position), or cursor (pointer to next page).', analogy_en='Borrowing 10 library books at a time. Can''t carry them all at once, so borrow in batches.', pitfall_en='Offset-based pagination slows with large data. Cursor-based is more efficient.' WHERE id='pagination-api';
UPDATE terms SET one_liner_en='Managing API versions', definition_en='Managing different versions of an API while maintaining backward compatibility and adding new features.', mechanism_en='Common approach: include version in URL like /v1/users, /v2/users.', analogy_en='Legal amendments. Old laws remain valid while new ones are added.', pitfall_en='Too many versions become hard to manage. Phase out old versions systematically.' WHERE id='versioning';
UPDATE terms SET one_liner_en='Warning that an old feature is being retired', definition_en='Marking an old API or feature as "scheduled for removal" and encouraging migration to newer methods.', mechanism_en='Warnings are given in documentation and response headers. Actual removal follows after a grace period.', analogy_en='A store closure notice. "This location closes next month. Please visit our new store next door."', pitfall_en='Continuing to use deprecated APIs is risky. Switch to new APIs during the migration period.' WHERE id='deprecation';
UPDATE terms SET one_liner_en='Same result no matter how many times you execute', definition_en='The property that sending the same request multiple times always produces the same result. GET, PUT, DELETE are idempotent; POST is not.', mechanism_en='Sending DELETE /users/123 multiple times always results in "ID 123 is deleted."', analogy_en='Pressing a light switch to "off." No matter how many times you press, it stays off.', pitfall_en='Retrying non-idempotent operations requires care. Need mechanisms to prevent duplicate processing.' WHERE id='idempotent';
UPDATE terms SET one_liner_en='Try again after failure', definition_en='A mechanism that automatically retries when an API request fails. Handles temporary failures.', mechanism_en='Retry with exponential backoff (1s, 2s, 4s... increasing intervals). Set a maximum retry count.', analogy_en='Calling back when the line is busy. If it fails once, wait a bit and try again.', pitfall_en='Too many retries overload the server. Set appropriate max count and intervals.' WHERE id='retry';
UPDATE terms SET one_liner_en='An alternative when the primary method fails', definition_en='An alternative approach used when the primary method fails. Return cached data, use default values, etc.', mechanism_en='Catch errors with try-catch and execute fallback processing on error.', analogy_en='An emergency exit. When the normal exit is unusable, an alternative route is available.', pitfall_en='Fallbacks can also fail. Prepare multiple layers of fallback strategies.' WHERE id='fallback';
UPDATE terms SET one_liner_en='Documentation explaining how to use an API', definition_en='Documentation explaining an API''s endpoints, parameters, response formats, authentication methods, etc. Can be auto-generated with Swagger/OpenAPI.', mechanism_en='Lists endpoints, request/response examples, error codes, authentication methods, etc.', analogy_en='An instruction manual. Detailed instructions on how to use the product (API).', pitfall_en='Keep documentation in sync with the implementation. Discrepancies cause confusion.' WHERE id='api-documentation';

-- ═══════════════════════════════════════
-- Epilogue: Memory Garden (20 terms)
-- ═══════════════════════════════════════

UPDATE terms SET one_liner_en='A syntax for catching and handling errors', definition_en='A syntax that wraps potentially error-prone code in try, and catches and handles errors in catch.', mechanism_en='try { risky code } catch (error) { error handling }. Can also use finally for cleanup.', analogy_en='A safety net. If you fall (error) from the trapeze, the net (catch) catches you.', pitfall_en='Don''t wrap everything in try/catch — use it appropriately where errors are likely.' WHERE id='try-catch';
UPDATE terms SET one_liner_en='Two values representing "nothing"', definition_en='null means "intentionally empty"; undefined means "no value has been set yet." Similar but different in meaning.', mechanism_en='let x; is undefined. let y = null; is intentionally empty. typeof null returns ''object'' (historical bug).', analogy_en='An empty box (null) vs. a box that doesn''t exist yet (undefined).', pitfall_en='With ==, null == undefined is true. With ===, it''s false. Use strict equality.' WHERE id='null-undefined';
UPDATE terms SET one_liner_en='A (?.) syntax for safely accessing properties', definition_en='A syntax for safely accessing properties that might not exist, without throwing errors.', mechanism_en='user?.address?.city returns undefined instead of throwing an error if anything along the chain is null/undefined.', analogy_en='Careful knocking. Checking "Anyone home?" at each door before entering.', pitfall_en='Convenient for existence checks, but overuse can hide bugs.' WHERE id='optional-chaining';
UPDATE terms SET one_liner_en='A (??) operator that uses alternatives only for null/undefined', definition_en='An operator that uses the right-hand value only when the left side is null or undefined. Unlike ||, treats 0 and '''' as valid values.', mechanism_en='value ?? ''default'' returns ''default'' only when value is null or undefined.', analogy_en='Using a backup only when truly empty. $0 is still "something"; unset is "nothing."', pitfall_en='|| replaces all falsy values (0, '''', false too). ?? only replaces null/undefined.' WHERE id='nullish-coalescing';
UPDATE terms SET one_liner_en='Backtick strings that can embed variables', definition_en='Strings enclosed in backticks (`) that can embed variables and expressions with ${}. Multi-line strings are also easy.', mechanism_en='`Hello, ${name}!` — more readable than concatenation with +.', analogy_en='A fill-in-the-blank question. The blank in "Hello, ___" is automatically filled with the variable''s value.', pitfall_en='Don''t confuse backticks (`) with single quotes ('').' WHERE id='template-literal';
UPDATE terms SET one_liner_en='condition ? trueValue : falseValue', definition_en='An operator that writes a conditional expression in one line. Returns the first value if true, the second if false.', mechanism_en='isLoggedIn ? ''Welcome'' : ''Please login'' — a shorthand for if-else.', analogy_en='A two-choice quiz. "Correct = A, Wrong = B" expressed in a single line.', pitfall_en='Nesting makes it hard to read. Use if-else for complex conditions.' WHERE id='ternary-operator';
UPDATE terms SET one_liner_en='Persistent data storage in the browser', definition_en='A mechanism for storing key-value pairs in the browser. Data persists even after closing the browser.', mechanism_en='localStorage.setItem(''key'', ''value'') to save, getItem(''key'') to retrieve. Only stores strings.', analogy_en='A browser''s drawer. What you put in stays even after closing the browser.', pitfall_en='Objects must be converted to strings with JSON.stringify() before saving. Use JSON.parse() when retrieving.' WHERE id='localstorage';
UPDATE terms SET one_liner_en='A flexible CSS layout for arranging elements', definition_en='A CSS layout method for flexibly arranging elements in rows or columns with easy alignment and spacing control.', mechanism_en='Enable with display: flex;. Control layout with justify-content and align-items.', analogy_en='Dancers in formation. "Line up horizontally," "gather in the center" — easily directed.', pitfall_en='Flex is 1-dimensional (row or column). Use Grid for 2-dimensional layouts.' WHERE id='flexbox';
UPDATE terms SET one_liner_en='A 2-dimensional grid layout', definition_en='A CSS layout method for placing elements in a 2D grid of rows and columns. Best for complex layouts.', mechanism_en='Enable with display: grid;. Define the grid with grid-template-columns and grid-template-rows.', analogy_en='Excel cells. Place elements in cells divided by rows and columns.', pitfall_en='Use Flexbox vs Grid appropriately. 1D = Flex, 2D = Grid.' WHERE id='grid-css';
UPDATE terms SET one_liner_en='Specifies element stacking order', definition_en='A CSS property that specifies the front-to-back order when elements overlap. Higher values appear in front.', mechanism_en='z-index: 100; — only works when position is not static.', analogy_en='Paper stacking order. The paper with higher z-index goes on top.', pitfall_en='z-index values tend to inflate. Use planned values (10, 20, 30...) instead of 9999.' WHERE id='z-index';
UPDATE terms SET one_liner_en='The 4 regions that make up an element', definition_en='Every HTML element consists of 4 layers: content, padding (inner spacing), border (outline), margin (outer spacing).', mechanism_en='With box-sizing: border-box;, width includes padding and border.', analogy_en='A gift box. Contents (content) → cushioning (padding) → the box (border) → space to other boxes (margin).', pitfall_en='Default is content-box. border-box is easier to calculate, so it''s often set in CSS resets.' WHERE id='box-model';
UPDATE terms SET one_liner_en='Adapting layout to different screen sizes', definition_en='A design technique where layout changes to fit various screen sizes — PC, tablet, smartphone.', mechanism_en='Set breakpoints with media queries (@media). In Tailwind, use prefixes like md:, lg:.', analogy_en='Changing shape like water. Naturally adapting form to fit the container (screen).', pitfall_en='Designing mobile-first makes it easier to add large-screen support later.' WHERE id='responsive-design';
UPDATE terms SET one_liner_en='The screen width where layout switches', definition_en='The screen width threshold at which responsive design changes layout. Common values: 640px, 768px, 1024px.', mechanism_en='@media (min-width: 768px) { } applies styles for tablet and above.', analogy_en='A transformation point. Cross this width and the layout transforms.', pitfall_en='Don''t confuse with debugger breakpoints. Determine meaning from context.' WHERE id='breakpoint-css';
UPDATE terms SET one_liner_en='A number indicating the HTTP response result', definition_en='A 3-digit number in server responses. 200 (success), 404 (not found), 500 (server error), etc.', mechanism_en='1xx: info, 2xx: success, 3xx: redirect, 4xx: client error, 5xx: server error.', analogy_en='Diagnosis results. "Healthy (200)," "Not found (404)," "Our fault (500)."', pitfall_en='4xx = client-side problem, 5xx = server-side problem. Useful for troubleshooting.' WHERE id='status-code';
UPDATE terms SET one_liner_en='Publishing an app to production', definition_en='Placing a developed application on a production server and making it accessible to users.', mechanism_en='Build → upload to server → publish. Vercel, Netlify, etc. auto-deploy on git push.', analogy_en='Opening a store. Preparations are done — time to welcome customers.', pitfall_en='Test thoroughly before deploying. Production issues have major impact.' WHERE id='deploy';
UPDATE terms SET one_liner_en='A service for publishing websites', definition_en='Server services for making websites and applications publicly available on the internet.', mechanism_en='Options include Vercel, Netlify, AWS, etc. Types for static sites, dynamic sites, and more.', analogy_en='Renting a storefront. A location to put your products (site) and welcome visitors.', pitfall_en='Free plans have limitations. Consider paid plans based on traffic and feature needs.' WHERE id='hosting';
UPDATE terms SET one_liner_en='A website''s address (URL)', definition_en='A human-readable name like example.com that identifies a website. Used instead of IP addresses.', mechanism_en='DNS converts domain names to IP addresses. Custom domains are purchased and configured.', analogy_en='A store''s signboard. A name (domain) is easier to remember than an address (IP).', pitfall_en='Domains are first-come, first-served. Get desired names early. Annual renewal fees apply.' WHERE id='domain';
UPDATE terms SET one_liner_en='Encrypting communication for safety', definition_en='A protocol that encrypts communication using SSL (TLS) certificates. URLs start with https://. Shows a lock icon.', mechanism_en='Encrypts communication between server and browser. Prevents eavesdropping and tampering. Free via Let''s Encrypt.', analogy_en='An encrypted letter. Even if someone intercepts it, they can''t read the contents.', pitfall_en='HTTPS is mandatory for modern web. HTTP triggers "Not Secure" warnings.' WHERE id='ssl-https';
UPDATE terms SET one_liner_en='Optimizing for higher search engine rankings', definition_en='Short for Search Engine Optimization. Optimizing a site to appear higher in Google and other search results.', mechanism_en='Important factors: proper titles, meta descriptions, structured data, fast loading, mobile-friendliness.', analogy_en='Making a store easy to find. Eye-catching signage and correct map listings.', pitfall_en='Don''t sacrifice user experience for SEO. Good content is the most important factor.' WHERE id='seo';
UPDATE terms SET one_liner_en='Making things usable by everyone', definition_en='Ensuring all people can use websites and apps regardless of disabilities. Abbreviated as a11y.', mechanism_en='Semantic HTML, ARIA attributes, keyboard navigation, color contrast, alt text, etc.', analogy_en='Barrier-free design. Buildings everyone can enter — wheelchair users, visually impaired, everyone.', pitfall_en='Don''t add accessibility last — design with it in mind from the start.' WHERE id='accessibility';

-- Notify PostgREST to reload schema
NOTIFY pgrst, 'reload schema';
